export const footerCopyrightText = (t: TranslateFn): BlockItem => ({
  title: t('block.footerCopyrightText.title'),
  description: t('block.footerCopyrightText.description'),
  searchTerms: ['footer', 'copyright'],
  icon: <IconPlaceholder
