  tabler="IconCopyright"
  hugeicons="CopyrightIcon"
  phosphor="Copyright"
  remixicon="RiCopyrightLine"
  className="h-4 w-4"
/>,
  command: ({ editor, range }) => {
    const currentYear = new Date().getFullYear();

    editor
      .chain()
      .focus()
      .deleteRange(range)
      .insertContent({
        type: 'paragraph',
        attrs: { textAlign: 'center', showIfKey: null },
