import { AlignCenter, AlignLeft, AlignRight, BoldIcon, EraserIcon, ItalicIcon, LinkIcon, SeparatorHorizontal, StrikethroughIcon, UnderlineIcon } from "lucide-react"
import { useMemo } from 'react';
import { Editor as EditorType } from '@tiptap/core';
import { EditorProps } from '..';
import { cn } from '@/lib/utils';
import { BubbleMenuButton } from './bubble-menu-button';
import { BubbleMenuItem } from './text-menu/text-bubble-menu';

interface EditorMenuItem extends BubbleMenuItem {
  group: 'alignment' | 'image' | 'mark' | 'custom' | 'email';
}

type EditorMenuBarProps = {
  config: EditorProps['config'];
  editor: EditorType;
};

export const EditorMenuBar = (props: EditorMenuBarProps) => {
  const { editor, config } = props;

  const items: EditorMenuItem[] = useMemo(
    () => [
      {
        name: 'bold',
        command: () => editor.chain().focus().toggleBold().run(),
        isActive: () => editor.isActive('bold'),
        group: 'mark',
        icon: BoldIcon,
      },
      {
        name: 'italic',
        command: () => editor.chain().focus().toggleItalic().run(),
        isActive: () => editor.isActive('italic'),
        group: 'mark',
        icon: ItalicIcon,
      },
      {
        name: 'underline',
        command: () => editor.chain().focus().toggleUnderline().run(),
        isActive: () => editor.isActive('underline'),
        group: 'mark',
        icon: UnderlineIcon,
      },
      {
        name: 'strike',
        command: () => editor.chain().focus().toggleStrike().run(),
        isActive: () => editor.isActive('strike'),
        group: 'mark',
        icon: StrikethroughIcon,
      },
      {
        name: 'delete-line',
        command: () =>
          editor.chain().focus().selectParentNode().deleteSelection().run(),
        isActive: () => false,
        group: 'mark',
        icon: EraserIcon,
      },
      {
        name: 'divider',
        command: () => editor.chain().focus().setHorizontalRule().run(),
        isActive: () => editor.isActive('horizontalRule'),
        group: 'custom',
        icon: SeparatorHorizontal,
      },
      {
        name: 'link',
        command: () => {
          const previousUrl = editor.getAttributes('link').href;
          const url = window.prompt('URL', previousUrl);
          // If the user cancels the prompt, we don't want to toggle the link
          if (url === null) return;
          // If the user deletes the URL entirely, we'll unlink the selected text
          if (url === '') {
            editor.chain().focus().extendMarkRange('link').unsetLink().run();
            return;
          }

          // Otherwise, we set the link to the given URL
          editor
            .chain()
            .focus()
            .extendMarkRange('link')
            .setLink({ href: url })
            .run();
        },
        isActive: () => editor.isActive('link'),
        group: 'custom',
        icon: LinkIcon,
      },
      {
        name: 'left',
        command: () => editor.chain().focus().setTextAlign('left').run(),
        isActive: () => editor.isActive({ textAlign: 'left' }),
        group: 'alignment',
        icon: AlignLeft,
      },
      {
        name: 'center',
        command: () => editor.chain().focus().setTextAlign('center').run(),
        isActive: () => editor.isActive({ textAlign: 'center' }),
        group: 'alignment',
        icon: AlignCenter,
      },
      {
        name: 'right',
        command: () => editor.chain().focus().setTextAlign('right').run(),
        isActive: () => editor.isActive({ textAlign: 'right' }),
        group: 'alignment',
        icon: AlignRight,
      },
    ],
    [editor]
  );

  const groups = useMemo(
    () =>
      items.reduce((acc, item) => {
        if (!acc.includes(item.group)) {
          acc.push(item.group);
        }
        return acc;
      }, [] as string[]),
    [items]
  );

  if (!editor) {
    return null;
  }

  return (
    <div className={cn('flex items-center gap-3', config?.toolbarClassName)}>
      {groups.map((group, index) => (
        <div
          key={index}
          className="border-border bg-background flex items-center gap-1 rounded-md border p-1"
        >
          {items
            .filter((item) => item.group === group)
            .map((item, index) => (
              <BubbleMenuButton key={index} {...item} />
            ))}
        </div>
      ))}
    </div>
  );
};

