import { useMailyContext } from '../../provider';
import type { LabelKey } from '../../i18n';

export function SectionBubbleMenu(props: EditorBubbleMenuProps) {
  const { appendTo, editor } = props;
  if (!editor) {
    return null;
  }

  const getReferenceClientRect = useCallback(() => {
    const renderContainer = getRenderContainer(editor!, 'section');
    const rect =
      renderContainer?.getBoundingClientRect() ||
      new DOMRect(-1000, -1000, 0, 0);

    return rect;
  }, [editor]);

  const bubbleMenuProps: EditorBubbleMenuProps = {
    ...props,
    ...(appendTo ? { appendTo: appendTo.current } : {}),
    shouldShow: ({ editor }) => {
      const activeSectionNode = getClosestNodeByName(editor, 'section');
      const repeatNodeChildren = activeSectionNode
        ? findChildren(activeSectionNode?.node, (node) => {
            return node.type.name === 'repeat';
          })?.[0]
        : null;
      const inlineImageNodeChildren = activeSectionNode
        ? findChildren(activeSectionNode?.node, (node) => {
            return node.type.name === 'inlineImage';
          })?.[0]
        : null;
      const hasActiveRepeatNodeChildren =
        repeatNodeChildren && editor.isActive('repeat');
      const hasActiveInlineImageNodeChildren =
        inlineImageNodeChildren && editor.isActive('inlineImage');

      if (
        isTextSelected(editor) ||
        hasActiveRepeatNodeChildren ||
        hasActiveInlineImageNodeChildren ||
        !editor.isEditable
      ) {
        return false;
      }

      return editor.isActive('section');
    },
    tippyOptions: {
      offset: [0, 8],
      popperOptions: {
        modifiers: [{ name: 'flip', enabled: false }],
      },
      getReferenceClientRect,
      appendTo: () => appendTo?.current,
      plugins: [sticky],
      sticky: 'popper',
      maxWidth: 'auto',
    },
    pluginKey: 'sectionBubbleMenu',
  };

  const state = useSectionState(editor);
  const { t } = useMailyContext();

  const borderRadiusOptions = [
    { value: '0', label: t('sectionMenu.radius.sharp') },
    { value: '6', label: t('sectionMenu.radius.smooth') },
    { value: '9999', label: t('sectionMenu.radius.round') },
  ];

  const spacingOptions = (noneKey: LabelKey) => [
    { value: '0', label: t(noneKey) },
    ...spacing.map((space) => ({
      label: t(`spacing.${space.short}` as LabelKey),
      value: String(space.value),
    })),
  ];

  return (
    <BubbleMenu
      {...bubbleMenuProps}
      className="border-border bg-background flex items-stretch rounded-lg border p-0.5 shadow-md"
    >
      <TooltipProvider>
        <AlignmentSwitch
          alignment={state.currentAlignment}
          onAlignmentChange={(alignment) => {
            editor?.commands?.updateSection({
              align: alignment,
            });
          }}
        />

        <Divider />

        <div className="flex gap-x-0.5">
          <Select
            label={t('sectionMenu.borderRadius')}
            value={String(state.currentBorderRadius)}
            options={borderRadiusOptions}
            onValueChange={(value) => {
              editor?.commands?.updateSection({
                borderRadius: Number(value),
              });
            }}
            tooltip={t('sectionMenu.borderRadius')}
            className="capitalize"
          />

          <Select
            label={t('sectionMenu.borderWidth')}
            value={String(state.currentBorderWidth)}
            options={[
              { value: '0', label: t('sectionMenu.borderWidth.none') },
              { value: '1', label: t('sectionMenu.borderWidth.thin') },
              { value: '2', label: t('sectionMenu.borderWidth.medium') },
              { value: '3', label: t('sectionMenu.borderWidth.thick') },
            ]}
            onValueChange={(value) => {
              editor?.commands?.updateSection({
                borderWidth: Number(value),
              });
            }}
            tooltip={t('sectionMenu.borderWidth')}
            className="capitalize"
          />
        </div>

        <Divider />

        <Select
          icon={MarginIcon}
          iconClassName="stroke-[1.2] size-3.5"
          label={t('sectionMenu.margin')}
          value={String(state.currentMarginTop)}
          options={spacingOptions('sectionMenu.margin.none')}
          onValueChange={(_value) => {
            const value = Number(_value);
            editor?.commands?.updateSection({
              marginTop: value,
              marginRight: value,
              marginBottom: value,
              marginLeft: value,
            });
          }}
          tooltip={t('sectionMenu.margin')}
          className="capitalize"
        />

        <Divider />

        <Select
          icon={PaddingIcon}
          iconClassName="stroke-[1]"
          label={t('sectionMenu.padding')}
          value={String(state.currentPaddingTop)}
          options={spacingOptions('sectionMenu.padding.none')}
          onValueChange={(_value) => {
            const value = Number(_value);
            editor?.commands?.updateSection({
              paddingTop: value,
              paddingRight: value,
              paddingBottom: value,
              paddingLeft: value,
            });
          }}
          tooltip={t('sectionMenu.padding')}
          className="capitalize"
        />

        <Divider />

        <div className="flex gap-x-0.5">
          <ColorPicker
            color={state.currentBorderColor}
            onColorChange={(color) => {
              editor?.commands?.updateSection({
                borderColor: color,
              });
            }}
            tooltip={t('sectionMenu.borderColor')}
          >
            <BaseButton
              variant="ghost"
              className="h-7 w-7 shrink-0"
              size="sm"
              type="button"
            >
              <BorderColor
                className="size-3 shrink-0"
                topBarClassName="stroke-foreground"
                style={{
                  color: state.currentBorderColor,
                }}
              />
            </BaseButton>
          </ColorPicker>
          <ColorPicker
            color={state.currentBackgroundColor}
            onColorChange={(color) => {
              editor?.commands?.updateSection({
                backgroundColor: color,
              });
            }}
            backgroundColor={state.currentBackgroundColor}
            tooltip={t('sectionMenu.backgroundColor')}
            className="border-background rounded-full border-[1.5px] shadow"
          />
        </div>

        <Divider />

        <BubbleMenuButton
          icon={Trash}
          tooltip={t('sectionMenu.delete')}
          command={() => {
            deleteNode(editor, 'section');
          }}
        />

        <Divider />

        <ShowPopover
          showIfKey={state.currentShowIfKey}
          onShowIfKeyValueChange={(value) => {
            editor.commands.updateSection({
              showIfKey: value,
            });
          }}
          editor={editor}
        />

        {state.isColumnsActive && (
          <>
            <Divider />
            <Popover>
              <PopoverTrigger className="data-[state=open]:bg-accent data-[state=open]:text-accent-foreground hover:bg-accent hover:text-accent-foreground flex items-center gap-1 rounded-md px-1.5 text-sm">
                {t('sectionMenu.column')}
                <IconPlaceholder
  lucide="ChevronUp"
  tabler="IconChevronUp"
  hugeicons="ChevronUpIcon"
  phosphor="CaretUp"
  remixicon="RiArrowUpSLine"
  className="h-3 w-3"
/>
              </PopoverTrigger>
              <PopoverContent
                className="w-max rounded-lg p-0.5!"
                side="top"
                sideOffset={8}
                align="end"
                onOpenAutoFocus={(e) => {
                  e.preventDefault();
                }}
                onCloseAutoFocus={(e) => {
                  e.preventDefault();
                }}
              >
                <ColumnsBubbleMenuContent editor={editor} />
              </PopoverContent>
            </Popover>
          </>
        )}
      </TooltipProvider>
    </BubbleMenu>
  );
}

import {
  DEFAULT_SECTION_BACKGROUND_COLOR,
  DEFAULT_SECTION_BORDER_COLOR,
} from '../../nodes/section/section';
import { Editor, useEditorState } from '@tiptap/react';
import deepEql from 'fast-deep-equal';

export const useSectionState = (editor: Editor) => {
  const states = useEditorState({
    editor,
    selector: (ctx) => {
      return {
        currentAlignment: ctx.editor.getAttributes('section')?.align || 'left',

        currentBorderRadius:
          Number(ctx.editor.getAttributes('section')?.borderRadius) || 0,
        currentBackgroundColor:
          ctx.editor.getAttributes('section')?.backgroundColor ||
          DEFAULT_SECTION_BACKGROUND_COLOR,

        currentBorderColor:
          ctx.editor.getAttributes('section')?.borderColor ||
          DEFAULT_SECTION_BORDER_COLOR,
        currentBorderWidth:
          Number(ctx.editor.getAttributes('section')?.borderWidth) || 0,

        currentMarginTop:
          Number(ctx.editor.getAttributes('section')?.marginTop) || 0,
        currentMarginRight:
          Number(ctx.editor.getAttributes('section')?.marginRight) || 0,
        currentMarginBottom:
          Number(ctx.editor.getAttributes('section')?.marginBottom) || 0,
        currentMarginLeft:
          Number(ctx.editor.getAttributes('section')?.marginLeft) || 0,

        currentPaddingTop:
          Number(ctx.editor.getAttributes('section')?.paddingTop) || 0,
        currentPaddingRight:
          Number(ctx.editor.getAttributes('section')?.paddingRight) || 0,
        currentPaddingBottom:
          Number(ctx.editor.getAttributes('section')?.paddingBottom) || 0,
        currentPaddingLeft:
          Number(ctx.editor.getAttributes('section')?.paddingLeft) || 0,

        isColumnsActive: ctx.editor.isActive('columns'),

        currentShowIfKey: ctx.editor.getAttributes('section')?.showIfKey || '',
      };
    },
    equalityFn: deepEql,
  });

  return states;
};

import { IconPlaceholder } from "@/components/icon-placeholder"
import { Editor } from '@tiptap/core';
import { memo, useMemo, useRef, useState } from 'react';
import { cn } from '@/lib/utils';
import { useVariableOptions } from '../utils/node-options';
import { processVariables } from '../utils/variable';
import { Popover, PopoverContent, PopoverTrigger } from './popover';
import { InputAutocomplete } from './ui/input-autocomplete';
import { Tooltip, TooltipContent, TooltipTrigger } from './ui/tooltip';
import { useMailyContext } from '../provider';

type ShowPopoverProps = {
  showIfKey?: string;
  onShowIfKeyValueChange?: (when: string) => void;

  editor: Editor;
};

function _ShowPopover(props: ShowPopoverProps) {
  const { showIfKey = '', onShowIfKeyValueChange, editor } = props;
  const { t } = useMailyContext();

  const opts = useVariableOptions(editor);
  const variables = opts?.variables;
  const renderVariable = opts?.renderVariable;
  const [isUpdatingKey, setIsUpdatingKey] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  const autoCompleteOptions = useMemo(() => {
    return processVariables(variables, {
      query: showIfKey || '',
      from: 'bubble-variable',
      editor,
    }).map((variable) => variable.name);
  }, [variables, showIfKey, editor]);

  const isValidWhenKey = showIfKey || autoCompleteOptions.includes(showIfKey);

  return (
    <Popover
      onOpenChange={(open) => {
        if (open) {
          return;
        }

        setIsUpdatingKey(false);
      }}
    >
      <Tooltip>
        <TooltipTrigger asChild>
          <PopoverTrigger
            className={cn(
              'data-[state=open]:bg-accent data-[state=open]:text-accent-foreground hover:bg-accent hover:text-accent-foreground focus-visible:ring-ring flex size-7 items-center justify-center gap-1 rounded-md px-1.5 text-sm focus-visible:relative focus-visible:z-10 focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:outline-hidden',
              showIfKey &&
                'bg-rose-100 text-rose-800 hover:bg-rose-100 hover:text-rose-800 data-[state=open]:bg-rose-100 data-[state=open]:text-rose-800'
            )}
          >
            <IconPlaceholder
  lucide="Eye"
  tabler="IconEye"
  hugeicons="ViewIcon"
  phosphor="Eye"
  remixicon="RiEyeLine"
  className="h-3 w-3 stroke-[2.5]"
/>
          </PopoverTrigger>
        </TooltipTrigger>
        <TooltipContent sideOffset={8}>
          {t('showPopover.showConditionally')}
        </TooltipContent>
      </Tooltip>
      <PopoverContent
        className="flex w-max rounded-lg p-0.5!"
        side="top"
        sideOffset={8}
        align="end"
        onOpenAutoFocus={(e) => {
          e.preventDefault();
        }}
        onCloseAutoFocus={(e) => {
          e.preventDefault();
        }}
      >
        <div className="flex items-center gap-1.5 px-1.5 text-sm leading-none">
          {t('showPopover.showIf')}
          <Tooltip>
            <TooltipTrigger>
              <IconPlaceholder
  lucide="InfoIcon"
  tabler="IconInfoCircle"
  hugeicons="InformationCircleIcon"
  phosphor="Info"
  remixicon="RiInformationLine"
  className={cn('text-muted-foreground size-3 stroke-[2.5]')}
/>
            </TooltipTrigger>
            <TooltipContent
              sideOffset={14}
              className="max-w-[285px]"
              align="start"
            >
              {t('showPopover.showIfHint')}
            </TooltipContent>
          </Tooltip>
        </div>

        {!isUpdatingKey && (
          <button
            onClick={() => {
              setIsUpdatingKey(true);
              setTimeout(() => {
                inputRef.current?.focus();
              }, 0);
            }}
          >
            {renderVariable({
              variable: {
                name: showIfKey,
                valid: !!isValidWhenKey,
              },
              fallback: '',
              from: 'bubble-variable',
              editor,
            })}
          </button>
        )}
        {isUpdatingKey && (
          <form
            onSubmit={(e) => {
              e.preventDefault();
              setIsUpdatingKey(false);
            }}
            onKeyDown={(e) => {
              if (e.key === 'Escape') {
                setIsUpdatingKey(false);
              }
            }}
          >
            <InputAutocomplete
              editor={editor}
              value={showIfKey || ''}
              onValueChange={(value) => {
                onShowIfKeyValueChange?.(value);
              }}
              onOutsideClick={() => {
                setIsUpdatingKey(false);
              }}
              onSelectOption={(value) => {
                onShowIfKeyValueChange?.(value);
                setIsUpdatingKey(false);
              }}
              autoCompleteOptions={autoCompleteOptions}
              ref={inputRef}
            />
          </form>
        )}
      </PopoverContent>
    </Popover>
  );
}

export const ShowPopover = memo(_ShowPopover);

import { BubbleMenu } from '@tiptap/react';

import { BubbleMenuButton } from '../bubble-menu-button';
import {
  BubbleMenuItem,
  EditorBubbleMenuProps,
} from '../text-menu/text-bubble-menu';
import { Divider } from '../ui/divider';
import { useSpacerState } from './use-spacer-state';
import { ShowPopover } from '../show-popover';
import { TooltipProvider } from '../ui/tooltip';
import { spacing } from '../../utils/spacing';
import { useMemo } from 'react';

export function SpacerBubbleMenu(props: EditorBubbleMenuProps) {
  const { editor, appendTo } = props;
  if (!editor) {
    return null;
  }

  const items: BubbleMenuItem[] = useMemo(
    () =>
      spacing.map((space) => {
        const { value: height, short: name } = space;
        return {
          name,
          isActive: () => editor?.isActive('spacer', { height }),
          command: () => {
            editor?.chain().focus().setSpacer({ height }).run();
          },
        };
      }),
    [editor]
  );

  const bubbleMenuProps: EditorBubbleMenuProps = {
    ...props,
    ...(appendTo ? { appendTo: appendTo.current } : {}),
    shouldShow: ({ editor }) => {
      if (!editor.isEditable) {
        return false;
      }

      return editor.isActive('spacer');
    },
    tippyOptions: {
      maxWidth: '100%',
      moveTransition: 'transform 0.15s ease-out',
    },
  };

  const state = useSpacerState(editor);

  return (
    <BubbleMenu
      {...bubbleMenuProps}
      className="border-border bg-background flex gap-0.5 rounded-lg border p-0.5 shadow-md"
    >
      <TooltipProvider>
        {items.map((item, index) => (
          <BubbleMenuButton
            key={index}
            className="!h-7 w-7 shrink-0 p-0"
            iconClassName="w-3 h-3"
            nameClassName="text-xs"
            {...item}
          />
        ))}
        <Divider />
        <ShowPopover
          showIfKey={state.currentShowIfKey}
          onShowIfKeyValueChange={(value) => {
            editor.commands.setSpacerShowIfKey(value);
          }}
          editor={editor}
        />
      </TooltipProvider>
    </BubbleMenu>
  );
}

