/>
          </PopoverTrigger>
        </TooltipTrigger>
        <TooltipContent sideOffset={8}>{t('turnInto.label')}</TooltipContent>
      </Tooltip>
      <PopoverContent
        align="start"
        side="bottom"
        sideOffset={8}
        className="flex w-[160px] flex-col rounded-md p-1"
      >
        {options.map((option, index) => {
          if (isOption(option)) {
            return (
              <BaseButton
                key={option.id}
                onClick={option.onClick}
                variant="ghost"
                className="text-foreground mb-0.5 h-auto justify-start gap-2 rounded! px-2 py-1 text-sm font-normal"
              >
                <option.icon className="size-[15px] shrink-0" />
                {option.label}
              </BaseButton>
            );
          } else if (isCategory(option)) {
            return (
              <label
                key={option.id}
                className={cn(
                  'text-foreground/60 px-2 text-xs font-medium',
                  index === 0 ? 'mt-1 mb-2' : 'my-2'
                )}
              >
                {option.label}
              </label>
            );
          }
        })}
      </PopoverContent>
    </Popover>
  );
}

import { AllowedLogoAlignment } from '../../nodes/logo/logo';
import {
  AllowedTextDirection,
  DEFAULT_TEXT_DIRECTION,
} from '../../nodes/paragraph/paragraph';
import { Editor, useEditorState } from '@tiptap/react';
import deepEql from 'fast-deep-equal';

export const DEFAULT_TEXT_COLOR = '#374151';

export const useTextMenuState = (editor: Editor) => {
  const states = useEditorState({
    editor,
    selector: (ctx) => {
      return {
        currentTextColor:
          ctx.editor.getAttributes('textStyle').color || DEFAULT_TEXT_COLOR,

        linkUrl: ctx.editor?.getAttributes('link').href,
        textAlign: (ctx.editor?.isActive({ textAlign: 'left' })
          ? 'left'
          : ctx.editor?.isActive({ textAlign: 'center' })
            ? 'center'
            : ctx.editor?.isActive({ textAlign: 'right' })
              ? 'right'
              : ctx.editor?.isActive({ textAlign: 'justify' })
                ? 'justify'
                : 'left') as AllowedLogoAlignment,

        textDirection: (ctx.editor.getAttributes('paragraph')?.textDirection ||
          ctx.editor.getAttributes('heading')?.textDirection ||
          ctx.editor.getAttributes('footer')?.textDirection ||
          DEFAULT_TEXT_DIRECTION) as AllowedTextDirection,

        isFooterActive: ctx.editor.isActive('footer'),
        footerTextDirection: (ctx.editor.getAttributes('footer')
          ?.textDirection || DEFAULT_TEXT_DIRECTION) as AllowedTextDirection,

        isListActive:
          ctx.editor.isActive('bulletList') ||
          ctx.editor.isActive('orderedList'),
        isUrlVariable: ctx.editor.getAttributes('link').isUrlVariable ?? false,

        isHeadingActive: ctx.editor.isActive('heading'),
        headingShowIfKey: ctx.editor.getAttributes('heading')?.showIfKey || '',

        isParagraphActive: ctx.editor.isActive('paragraph'),
        paragraphShowIfKey:
          ctx.editor.getAttributes('paragraph')?.showIfKey || '',
      };
    },
    equalityFn: deepEql,
  });

  return states;
};

import { FootprintsIcon, Heading1Icon, Heading2Icon, Heading3Icon, ListIcon, ListOrderedIcon, LucideIcon, PilcrowIcon } from "lucide-react"
import { Editor, useEditorState } from '@tiptap/react';
import { useMailyContext } from '../../provider';

export type TurnIntoBlockOptions = {
  label: string;
  id: string;
  type: 'option';
  disabled: () => boolean;
  isActive: () => boolean;
  onClick: () => void;
  icon: LucideIcon;
};

export type TurnIntoBlockCategory = {
  label: string;
  id: string;
  type: 'category';
};

export type TurnIntoOptions = Array<
  TurnIntoBlockOptions | TurnIntoBlockCategory
>;

export function useTurnIntoBlockOptions(editor: Editor) {
  const { t } = useMailyContext();
  return useEditorState({
    editor,
    selector: ({ editor }): TurnIntoOptions => [
      {
        type: 'category',
        label: t('turnInto.hierarchy'),
        id: 'hierarchy',
      },
      {
        icon: PilcrowIcon,
        onClick: () =>
          editor.chain().focus().liftListItem('listItem').setParagraph().run(),
        id: 'paragraph',
        disabled: () => !editor.can().setParagraph(),
        isActive: () =>
          editor.isActive('paragraph') &&
          !editor.isActive('orderedList') &&
          !editor.isActive('bulletList') &&
          !editor.isActive('taskList'),
        label: t('turnInto.paragraph'),
        type: 'option',
      },
      {
        icon: Heading1Icon,
        onClick: () =>
          editor
            .chain()
            .focus()
            .liftListItem('listItem')
            .setHeading({ level: 1 })
            .run(),
        id: 'heading1',
        disabled: () => !editor.can().setHeading({ level: 1 }),
        isActive: () => editor.isActive('heading', { level: 1 }),
        label: t('turnInto.heading1'),
        type: 'option',
      },
      {
        icon: Heading2Icon,
        onClick: () =>
          editor
            .chain()
            .focus()
            .liftListItem('listItem')
            .setHeading({ level: 2 })
            .run(),
        id: 'heading2',
        disabled: () => !editor.can().setHeading({ level: 2 }),
        isActive: () => editor.isActive('heading', { level: 2 }),
        label: t('turnInto.heading2'),
        type: 'option',
      },
      {
        icon: Heading3Icon,
        onClick: () =>
          editor
            .chain()
            .focus()
            .liftListItem('listItem')
            .setHeading({ level: 3 })
            .run(),
        id: 'heading3',
        disabled: () => !editor.can().setHeading({ level: 3 }),
        isActive: () => editor.isActive('heading', { level: 3 }),
        label: t('turnInto.heading3'),
        type: 'option',
      },
      {
        id: 'footer',
        type: 'option',
        label: t('turnInto.footer'),
        icon: FootprintsIcon,
        onClick: () => {
          editor.chain().focus().liftListItem('listItem').setFooter().run();
        },
        disabled: () => !editor.can().setFooter(),
        isActive: () => editor.isActive('footer'),
      },
      {
        type: 'category',
        label: t('turnInto.lists'),
        id: 'lists',
      },
      {
        icon: ListIcon,
        onClick: () => editor.chain().focus().toggleBulletList().run(),
        id: 'bulletList',
        disabled: () => !editor.can().toggleBulletList(),
        isActive: () => editor.isActive('bulletList'),
        label: t('turnInto.bulletList'),
        type: 'option',
      },
      {
        icon: ListOrderedIcon,
        onClick: () => editor.chain().focus().toggleOrderedList().run(),
        id: 'orderedList',
        disabled: () => !editor.can().toggleOrderedList(),
        isActive: () => editor.isActive('orderedList'),
        label: t('turnInto.numberedList'),
        type: 'option',
      },
