export function Divider(props: Props) {
  const { type = 'vertical', className } = props;

  return (
    <div
      className={cn(
        'bg-muted shrink-0',
        type === 'vertical' ? 'mx-0.5 w-px' : 'my-0.5 h-px',
        className
