        <InputWithLabel
          label={t('edgeSpacing.top')}
          value={top ?? 0}
          onChange={(value) => onTopValueChange?.(value)}
          inputClassName="rounded"
        />
        <InputWithLabel
          label={t('edgeSpacing.right')}
          value={right ?? 0}
