type InputWithLabelProps = {
  label: string;
  value: number;
  onChange: (value: number) => void;
  className?: string;
  inputClassName?: string;
};

function InputWithLabel(props: InputWithLabelProps) {
  const { label, value, onChange, className, inputClassName } = props;

  const id = `${label}${useId()}`;

  return (
    <div className={cn('flex flex-col items-center gap-1', className)}>
      <input
        {...AUTOCOMPLETE_PASSWORD_MANAGERS_OFF}
        id={id}
        min={0}
        type="number"
        // Error: https://github.com/facebook/react/issues/9402
        // adding `+ ''` to convert number to string so that number don't have leading zero(0)
        value={value + ''}
        onChange={(e) => onChange(Number(e.target.value))}
        className={cn(
          'bg-muted size-5 [appearance:textfield] border-0 border-none p-0.5 text-center text-xs tabular-nums outline-hidden focus-visible:outline-none [&::-webkit-inner-spin-button]:appearance-none [&::-webkit-outer-spin-button]:appearance-none',
          inputClassName
        )}
      />
      <label
        className="text-muted-foreground text-[10px] leading-none"
        htmlFor={id}
      >
        {label}
      </label>
    </div>
  );
}

import { IconPlaceholder } from "@/components/icon-placeholder"
import { VariableSuggestionsPopoverRef } from '../../nodes/variable/variable-suggestions-popover';
import { cn } from '@/lib/utils';
import { AUTOCOMPLETE_PASSWORD_MANAGERS_OFF } from '../../utils/constants';
import { useVariableOptions } from '../../utils/node-options';
import { useOutsideClick } from '../../utils/use-outside-click';
import { Editor } from '@tiptap/core';
import { forwardRef, HTMLAttributes, useRef } from 'react';
import { useMailyContext } from '../../provider';

type InputAutocompleteProps = HTMLAttributes<HTMLInputElement> & {
  value: string;
  onValueChange: (value: string) => void;

  autoCompleteOptions?: string[];
  onSelectOption?: (option: string) => void;

  onOutsideClick?: () => void;
  triggerChar?: string;
  placeholder?: string;

  editor: Editor;
};

export const InputAutocomplete = forwardRef<
  HTMLInputElement,
  InputAutocompleteProps
>((props, ref) => {
  const {
    value = '',
    onValueChange,
    className,
    onOutsideClick,
    onSelectOption,
    autoCompleteOptions = [],
    triggerChar = '',
    editor,
    ...inputProps
  } = props;
  const { t } = useMailyContext();

  const containerRef = useRef<HTMLDivElement>(null);
  const popoverRef = useRef<VariableSuggestionsPopoverRef>(null);
  const VariableSuggestionPopoverComponent =
    useVariableOptions(editor)?.variableSuggestionsPopover;

  useOutsideClick(containerRef, () => {
    onOutsideClick?.();
  });

  const isTriggeringVariable = value.startsWith(triggerChar);

  return (
    <div className={cn('relative')} ref={containerRef}>
      <label className="relative">
        <input
          {...AUTOCOMPLETE_PASSWORD_MANAGERS_OFF}
          placeholder={t('inputAutocomplete.placeholder')}
          type="text"
          {...inputProps}
          ref={ref}
          value={value}
          onChange={(e) => {
            onValueChange(e.target.value);
          }}
          className={cn(
            'bg-background text-foreground hover:bg-muted focus:bg-muted h-7 w-40 rounded-md px-2 pr-6 text-sm focus:outline-hidden',
            className
          )}
          onKeyDown={(e) => {
            if (!popoverRef.current || !isTriggeringVariable) {
              return;
            }
            const { moveUp, moveDown, select } = popoverRef.current;

            if (e.key === 'ArrowDown') {
              e.preventDefault();
              moveDown();
            } else if (e.key === 'ArrowUp') {
              e.preventDefault();
              moveUp();
            } else if (e.key === 'Enter') {
              e.preventDefault();
              select();
            }
          }}
          spellCheck={false}
        />
        <div className="absolute inset-y-0 right-1 flex items-center">
          <IconPlaceholder
  lucide="CornerDownLeft"
  tabler="IconCornerDownLeft"
  hugeicons="CornerDownLeftIcon"
  phosphor="ArrowBendDownLeft"
  remixicon="RiCornerDownLeftLine"
  className="text-foreground h-3 w-3 stroke-[2.5]"
/>
        </div>
      </label>

      {isTriggeringVariable && (
        <div className="absolute top-8 left-0">
          <VariableSuggestionPopoverComponent
            items={autoCompleteOptions.map((option) => {
              return {
                name: option,
              };
            })}
            onSelectItem={(item) => {
              onSelectOption?.(item.name);
            }}
            ref={popoverRef}
          />
        </div>
      )}
    </div>
  );
});

InputAutocomplete.displayName = 'InputAutocomplete';

import { IconPlaceholder } from "@/components/icon-placeholder"
import { Link, LucideIcon } from "lucide-react"
import { Popover, PopoverContent, PopoverTrigger } from '../popover';
import { BaseButton } from '../base-button';
import { useRef, useState } from 'react';
import { Tooltip, TooltipTrigger, TooltipContent } from './tooltip';
import { DEFAULT_PLACEHOLDER_URL, useMailyContext } from '../../provider';
import { InputAutocomplete } from './input-autocomplete';
import { processVariables } from '../../utils/variable';
import { useMemo } from 'react';
import { Editor } from '@tiptap/core';
import { useVariableOptions } from '../../utils/node-options';
import { DEFAULT_VARIABLE_TRIGGER_CHAR } from '../../nodes/variable/variable';

type LinkInputPopoverProps = {
  defaultValue?: string;
  isVariable?: boolean;
  onValueChange?: (value: string, isVariable?: boolean) => void;

  icon?: LucideIcon;
  tooltip?: string;

  editor: Editor;
};

export function LinkInputPopover(props: LinkInputPopoverProps) {
  const {
    defaultValue = '',
    onValueChange,
    tooltip,
    icon: Icon = Link,
    editor,

    isVariable,
  } = props;

  const [isOpen, setIsOpen] = useState(false);
  const [isEditing, setIsEditing] = useState(!isVariable);

  const linkInputRef = useRef<HTMLInputElement>(null);

  const { placeholderUrl = DEFAULT_PLACEHOLDER_URL } = useMailyContext();
  const options = useVariableOptions(editor);

  const renderVariable = options?.renderVariable;
  const variables = options?.variables;
  const variableTriggerCharacter =
    options?.suggestion?.char ?? DEFAULT_VARIABLE_TRIGGER_CHAR;

  const autoCompleteOptions = useMemo(() => {
    const withoutTrigger = defaultValue.replace(
      new RegExp(variableTriggerCharacter, 'g'),
      ''
    );

    return processVariables(variables, {
      query: withoutTrigger || '',
      from: 'bubble-variable',
      editor,
    }).map((variable) => variable.name);
  }, [variables, variableTriggerCharacter, defaultValue, editor]);

  const popoverButton = (
    <PopoverTrigger asChild>
      <BaseButton
        variant="ghost"
        size="sm"
        type="button"
        className="h-7! w-7!"
        data-state={!!defaultValue}
      >
        <Icon className="text-foreground h-3 w-3 shrink-0 stroke-[2.5]" />
      </BaseButton>
    </PopoverTrigger>
  );

  return (
    <Popover
      open={isOpen}
      onOpenChange={(open) => {
        setIsOpen(open);
        if (open) {
          setTimeout(() => {
            linkInputRef.current?.focus();
          }, 0);
        }
      }}
    >
      {tooltip ? (
        <Tooltip>
          <TooltipTrigger asChild>{popoverButton}</TooltipTrigger>
          <TooltipContent sideOffset={8}>{tooltip}</TooltipContent>
        </Tooltip>
      ) : (
        popoverButton
      )}

      <PopoverContent
        align="end"
        side="top"
        className="w-max rounded-none border-none bg-transparent p-0! shadow-none"
        sideOffset={8}
        onCloseAutoFocus={(e) => e.preventDefault()}
      >
        <form
          onSubmit={(e) => {
            e.preventDefault();
            const input = linkInputRef.current;
            if (!input) {
              return;
            }

            onValueChange?.(input.value);
            setIsOpen(false);
          }}
        >
          <div className="isolate flex rounded-lg">
            {!isEditing && (
              <div className="border-border bg-background flex h-8 items-center rounded-lg border px-0.5">
                <button
                  onClick={() => {
                    setIsEditing(true);
                    setTimeout(() => {
                      linkInputRef.current?.focus();
                    }, 0);
                  }}
                >
                  {renderVariable({
                    variable: {
                      name: defaultValue,
                      valid: true,
                    },
                    fallback: '',
                    from: 'bubble-variable',
                    editor,
                  })}
                </button>
              </div>
            )}

            {isEditing && (
              <div className="relative">
                <div className="absolute inset-y-0 left-1.5 z-10 flex items-center">
                  <IconPlaceholder
  lucide="LinkIcon"
  tabler="IconLink"
  hugeicons="Link01Icon"
  phosphor="Link"
  remixicon="RiLink"
  className="text-foreground h-3 w-3 stroke-[2.5]"
/>
                </div>

                <InputAutocomplete
                  editor={editor}
                  value={defaultValue}
                  onValueChange={(value) => {
                    onValueChange?.(value);
                  }}
                  autoCompleteOptions={autoCompleteOptions}
                  ref={linkInputRef}
                  placeholder={placeholderUrl}
                  className="border-border placeholder:text-muted-foreground -ms-px block h-8 w-56 rounded-lg border px-2 py-1.5 pr-6 pl-6 text-sm shadow-sm outline-hidden"
                  triggerChar={variableTriggerCharacter}
                  onSelectOption={(value) => {
                    const isVariable =
                      autoCompleteOptions.includes(value) ?? false;
                    if (isVariable) {
                      setIsEditing(false);
                    }

                    onValueChange?.(value, isVariable);
                    setIsOpen(false);
                  }}
                />
              </div>
            )}
          </div>
        </form>
      </PopoverContent>
    </Popover>
  );
}

import { type LucideIcon } from "lucide-react"
import { forwardRef } from 'react';
import { cn } from '@/lib/utils';
import { SVGIcon } from '../icons/grid-lines';
import { Tooltip, TooltipContent, TooltipTrigger } from './tooltip';
import { AUTOCOMPLETE_PASSWORD_MANAGERS_OFF } from '../../utils/constants';

type NumberInputProps = {
  value: number;
  onValueChange: (value: number) => void;
  icon?: LucideIcon | SVGIcon;
  max?: number;

  tooltip?: string;
};

export const NumberInput = forwardRef<HTMLLabelElement, NumberInputProps>(
  (props, ref) => {
    const { value, onValueChange, icon: Icon, max, tooltip } = props;

    const content = (
      <label ref={ref} className="relative flex items-center justify-center">
        {Icon ? <Icon className="absolute left-1.5 size-3.5" /> : null}
        <input
          {...AUTOCOMPLETE_PASSWORD_MANAGERS_OFF}
          min={0}
          {...(max ? { max } : {})}
          type="number"
          // Error: https://github.com/facebook/react/issues/9402
          // adding `+ ''` to convert number to string so that number don't have leading zero(0)
          value={value + ''}
          onChange={(e) => onValueChange(Number(e.target.value))}
          className={cn(
            'h-auto max-w-12 [appearance:textfield] border-0 border-none p-1 text-center text-sm tabular-nums outline-hidden focus-visible:outline-none [&::-webkit-inner-spin-button]:appearance-none [&::-webkit-outer-spin-button]:appearance-none',
            Icon ? 'pl-[26px]' : ''
          )}
        />
      </label>
    );

    if (tooltip) {
      return (
        <Tooltip>
          <TooltipTrigger asChild>
            <span>{content}</span>
          </TooltipTrigger>
          <TooltipContent sideOffset={8}>{tooltip}</TooltipContent>
        </Tooltip>
      );
    }

    return content;
  }
);

NumberInput.displayName = 'NumberInput';

import { IconPlaceholder } from "@/components/icon-placeholder"
import { LucideIcon } from "lucide-react"
import { useId } from 'react';
import { Tooltip, TooltipContent, TooltipTrigger } from './tooltip';
import { cn } from '@/lib/utils';
import { SVGIcon } from '../icons/grid-lines';

type SelectProps = {
  label: string;
  options: {
    value: string;
    label: string;
  }[];

  value: string;
  onValueChange: (value: string) => void;

  tooltip?: string;
  className?: string;

  icon?: LucideIcon | SVGIcon;
  iconClassName?: string;

  placeholder?: string;
};

export function Select(props: SelectProps) {
  const {
    label,
    options,
    value,
    onValueChange,
    tooltip,
    className,
    icon: Icon,
    iconClassName,
    placeholder,
  } = props;

  const selectId = `mly${useId()}`;

  const content = (
    <div className="relative">
      <label htmlFor={selectId} className="sr-only">
        {label}
      </label>

      {Icon && (
        <div className="pointer-events-none absolute inset-y-0 left-2 z-20 flex items-center">
          <Icon className={cn('size-3', iconClassName)} />
        </div>
      )}

      <select
        id={selectId}
        className={cn(
          'bg-background text-foreground ring-offset-background hover:bg-accent hover:text-accent-foreground focus-visible:ring-ring active:bg-accent active:text-accent-foreground flex min-h-7 max-w-max appearance-none items-center rounded-md px-1.5 py-0.5 pr-7 text-sm transition-colors focus-visible:relative focus-visible:z-10 focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:outline-hidden',
          !!Icon && 'pl-7',
          className
        )}
        value={value || ''}
        onChange={(event) => onValueChange(event.target.value)}
      >
        {placeholder && (
          <option value="" disabled hidden>
            {placeholder}
          </option>
        )}

        {options.map((option) => (
          <option key={option.value} value={option.value}>
            {option.label}
          </option>
        ))}
      </select>

      <span className="text-muted-foreground pointer-events-none absolute inset-y-0 right-0 z-10 flex h-full w-7 items-center justify-center peer-disabled:opacity-50">
        <IconPlaceholder
  lucide="ChevronDownIcon"
  tabler="IconChevronDown"
  hugeicons="ChevronDownIcon"
  phosphor="CaretDown"
  remixicon="RiArrowDownSLine"
  size={16}
          strokeWidth={2}
          aria-hidden="true"
          role="img"
/>
      </span>
    </div>
  );

  if (!tooltip) {
    return content;
  }

  return (
    <Tooltip>
      <TooltipTrigger asChild>{content}</TooltipTrigger>
      <TooltipContent sideOffset={8}>{tooltip}</TooltipContent>
    </Tooltip>
  );
}

'use client';

import * as React from 'react';
import * as TooltipPrimitive from '@radix-ui/react-tooltip';
import { cn } from '@/lib/utils';

// Explicit type annotations to avoid TS2742 errors
const TooltipProvider: React.FC<
  React.ComponentPropsWithoutRef<typeof TooltipPrimitive.Provider>
> = TooltipPrimitive.Provider;

const Tooltip: React.FC<
  React.ComponentPropsWithoutRef<typeof TooltipPrimitive.Root>
> = TooltipPrimitive.Root;

const TooltipTrigger: React.FC<
  React.ComponentPropsWithoutRef<typeof TooltipPrimitive.Trigger>
> = TooltipPrimitive.Trigger;

const TooltipContent = React.forwardRef<
  React.ElementRef<typeof TooltipPrimitive.Content>,
  React.ComponentPropsWithoutRef<typeof TooltipPrimitive.Content>
>(({ className, sideOffset = 4, ...props }, ref) => (
  <TooltipPrimitive.Content
    ref={ref}
    sideOffset={sideOffset}
    className={cn(
      'border-border bg-background animate-in fade-in-0 zoom-in-95 z-50 overflow-hidden rounded-md border px-2 py-1 text-xs',
      className
    )}
    {...props}
  />
)) as React.ForwardRefExoticComponent<
  React.ComponentPropsWithoutRef<typeof TooltipPrimitive.Content> &
    React.RefAttributes<React.ElementRef<typeof TooltipPrimitive.Content>>
>;

TooltipContent.displayName = TooltipPrimitive.Content.displayName;

export { Tooltip, TooltipTrigger, TooltipContent, TooltipProvider };

import { BubbleMenu } from '@tiptap/react';
import { sticky } from 'tippy.js';
import { TextBubbleContent } from '../text-menu/text-bubble-content';
import { EditorBubbleMenuProps } from '../text-menu/text-bubble-menu';
import { TooltipProvider } from '../ui/tooltip';

export function VariableBubbleMenu(props: EditorBubbleMenuProps) {
  const { editor, appendTo } = props;
  if (!editor) {
    return null;
  }

  const bubbleMenuProps: EditorBubbleMenuProps = {
    ...props,
    pluginKey: 'variable-menu',
    shouldShow: ({ editor }) => {
      return editor.isActive('variable') && !editor.storage.variable?.popover;
    },
    tippyOptions: {
      popperOptions: {
        modifiers: [{ name: 'flip', enabled: false }],
      },
      plugins: [sticky],
      sticky: 'popper',
      maxWidth: '100%',
      appendTo: () => appendTo?.current || 'parent',
      placement: 'top-start',
    },
  };

  return (
    <BubbleMenu
      {...bubbleMenuProps}
      className="border-border bg-background flex gap-0.5 rounded-lg border p-0.5 shadow-md"
    >
      <TooltipProvider>
        <TextBubbleContent showListMenu={false} editor={editor} />
      </TooltipProvider>
    </BubbleMenu>
  );
}

import { AlignVerticalDistributeCenter, AlignVerticalDistributeEnd, AlignVerticalDistributeStart } from "lucide-react"
import { BubbleMenuButton } from './bubble-menu-button';
import { AllowedColumnVerticalAlign } from '../nodes/columns/column';
import { useMailyContext } from '../provider';

type VerticalAlignmentSwitchProps = {
  alignment: AllowedColumnVerticalAlign;
  onAlignmentChange: (alignment: AllowedColumnVerticalAlign) => void;
};

export function VerticalAlignmentSwitch(props: VerticalAlignmentSwitchProps) {
  const { alignment = 'top', onAlignmentChange } = props;
  const { t } = useMailyContext();

  const activeAlignment = {
    top: {
      icon: AlignVerticalDistributeStart,
      tooltip: t('verticalAlignment.top'),
      onClick: () => {
        onAlignmentChange('middle');
      },
    },
    middle: {
      icon: AlignVerticalDistributeCenter,
      tooltip: t('verticalAlignment.center'),
      onClick: () => {
        onAlignmentChange('bottom');
      },
    },
    bottom: {
      icon: AlignVerticalDistributeEnd,
      tooltip: t('verticalAlignment.bottom'),
      onClick: () => {
        onAlignmentChange('top');
      },
    },
  }[alignment];

  return (
    <BubbleMenuButton
      icon={activeAlignment.icon}
      tooltip={activeAlignment.tooltip}
      command={activeAlignment.onClick}
    />
  );
}

