    };
  }
}

export const ColumnExtension = Node.create({
  name: 'column',
  content: 'block+',
  isolating: true,

  addAttributes() {
    return {
      columnId: {
        default: null,
        parseHTML: (element) =>
          element.getAttribute('data-column-id') || uuidv4(),
        renderHTML: (attributes) => {
          if (!attributes.columnId) {
            return {
              'data-column-id': uuidv4(),
            };
          }

          return {
            'data-column-id': attributes.columnId,
          };
        },
      },
      width: {
        default: DEFAULT_COLUMN_WIDTH,
        parseHTML: (element) =>
          element.style.width.replace(/['"]+/g, '') || DEFAULT_COLUMN_WIDTH,
        renderHTML: (attributes) => {
          if (!attributes.width || attributes.width === DEFAULT_COLUMN_WIDTH) {
            return {};
          }

          return {
            style: `width: ${attributes.width}%;max-width:${attributes.width}%`,
          };
        },
      },
      verticalAlign: {
        default: DEFAULT_COLUMN_VERTICAL_ALIGN,
        parseHTML: (element) => element?.style?.verticalAlign || 'top',
        renderHTML: (attributes) => {
          const { verticalAlign } = attributes;
          if (
            !verticalAlign ||
            verticalAlign === DEFAULT_COLUMN_VERTICAL_ALIGN
          ) {
            return {};
          }

          if (verticalAlign === 'middle') {
            return {
              style: `display: flex;flex-direction: column;justify-content: center;`,
            };
          } else if (verticalAlign === 'bottom') {
            return {
              style: `display: flex;flex-direction: column;justify-content: flex-end;`,
            };
          }
        },
      },
    };
  },

  addCommands() {
    return {
      updateColumn: (attrs) => updateAttributes(this.name, attrs),
    };
  },

  renderHTML({ HTMLAttributes }) {
    return [
      'div',
      mergeAttributes(HTMLAttributes, {
        'data-type': 'column',
        // table-cell + flex sizing, hidden scrollbars, reset edge margins, and a
        // solid outline when this column itself is focused.
        class:
          'table-cell basis-0 grow overflow-auto [scrollbar-width:none] [&::-webkit-scrollbar]:hidden [&>*:first-child]:mt-0 [&>*:last-child]:mb-0 [&.has-focus]:outline-solid',
      }),
      0,
    ];
  },

  parseHTML() {
    return [
      {
        tag: 'div[data-type="column"]',
      },
    ];
  },
});

