import { HtmlCodeBlockAttributes } from './html';

// highlight.js token colors for the HTML code view. These are literal
// syntax-theme colors (a code palette is its own thing, not the host's shadcn
// tokens), applied to the lowlight-generated `.hljs-*` spans via arbitrary
// variants so no editor stylesheet is required.
const HLJS_CLASS = [
  '[&_code]:bg-transparent [&_code]:text-inherit',
  '[&_:is(.hljs-comment,.hljs-quote)]:text-[#616161]',
  '[&_:is(.hljs-variable,.hljs-template-variable,.hljs-attribute,.hljs-regexp,.hljs-link,.hljs-selector-id,.hljs-selector-class,.hljs-name)]:text-[#00c951]',
  '[&_.hljs-tag]:text-[#313233]',
  '[&_:is(.hljs-number,.hljs-built\\_in,.hljs-builtin-name,.hljs-literal,.hljs-type,.hljs-params,.hljs-string,.hljs-symbol,.hljs-bullet,.hljs-selector-tag)]:text-[#2b7fff]',
  '[&_:is(.hljs-meta,.hljs-keyword)]:text-[#313233d6]',
  '[&_:is(.hljs-title,.hljs-section)]:text-[#faf594]',
  '[&_.hljs-attr]:text-[#ad46ff]',
  '[&_.hljs-emphasis]:italic [&_.hljs-strong]:font-bold',
].join(' ');

export function HTMLCodeBlockView(props: NodeViewProps) {
  const { node, updateAttributes } = props;

  let { language, activeTab = 'code' } = node.attrs as HtmlCodeBlockAttributes;
  activeTab ||= 'code';

  const languageClass = language ? `language-${language}` : '';

  const html = useMemo(() => {
    const text = node.content.content.reduce((acc, cur) => {
      if (cur.type.name === 'text') {
        return acc + cur.text;
      } else if (cur.type.name === 'variable') {
        const { id: variable, fallback } = cur?.attrs || {};
        const formattedVariable = fallback
          ? `{{${variable},fallback=${fallback}}}`
          : `{{${variable}}}`;
        return acc + formattedVariable;
      }

      return acc;
    }, '');

    const htmlParser = new DOMParser();
    const htmlDoc = htmlParser.parseFromString(text, 'text/html');
    const style = htmlDoc.querySelectorAll('style');
    const body = htmlDoc.body;
    const combinedStyle = Array.from(style)
      .map((s) => s.innerHTML)
      .join('\n');

    return `<style>${combinedStyle}</style>${body.innerHTML}`;
  }, [activeTab]);

  const isEmpty = html === '';

  return (
    <NodeViewWrapper
      draggable={false}
      data-drag-handle={false}
      data-type="htmlCodeBlock"
    >
      {activeTab === 'code' && (
        <pre
          className={cn(
            'border-border bg-background text-foreground my-0 rounded-lg border p-2',
            HLJS_CLASS
          )}
        >
          <NodeViewContent
            as="code"
            className={cn('is-editable', languageClass)}
          />
        </pre>
      )}

      {activeTab === 'preview' && (
        <div
          className={cn(
            'not-prose border-border rounded-lg border p-2',
            isEmpty && 'min-h-[42px]'
          )}
          ref={(node) => {
            if (!node || node?.shadowRoot) {
              return;
            }
            const shadow = node.attachShadow({ mode: 'open' });
            const sheet = new CSSStyleSheet();
            sheet.replaceSync(`
              * { font-family: 'Inter', sans-serif; }
              blockquote, h1, h2, h3, img, li, ol, p, ul {
                margin-top: 0;
                margin-bottom: 0;
              }
            `);
            shadow.adoptedStyleSheets = [sheet];
            const container = document.createElement('div');
            container.innerHTML = html;
            shadow.appendChild(container);
          }}
          contentEditable={false}
          onClick={() => {
            if (!isEmpty) {
              return;
            }

            updateAttributes({
              activeTab: 'code',
            });
          }}
        />
      )}
    </NodeViewWrapper>
  );
}

import { updateAttributes } from '../../utils/update-attribute';
import CodeBlockLowlight from '@tiptap/extension-code-block-lowlight';
import { TextSelection } from '@tiptap/pm/state';
import {
  NodeViewContent,
  NodeViewProps,
  NodeViewWrapper,
  ReactNodeViewRenderer,
} from '@tiptap/react';
import html from 'highlight.js/lib/languages/xml';
import { createLowlight, common } from 'lowlight';
import { HTMLCodeBlockView } from './html-view';
import { DEFAULT_SECTION_SHOW_IF_KEY } from '../../../extensions';

const lowlight = createLowlight(common);
lowlight.register('html', html);

export type HtmlCodeBlockAttributes = {
  activeTab: string;
  showIfKey: string;
  language: string;
};

declare module '@tiptap/core' {
  interface Commands<ReturnType> {
    htmlCodeBlock: {
      /**
       * Set a code block
       * @param attributes Code block attributes
       * @example editor.commands.setCodeBlock({ language: 'javascript' })
       */
      setHtmlCodeBlock: (attributes?: { language: string }) => ReturnType;
      /**
       * Toggle a code block
       * @param attributes Code block attributes
       * @example editor.commands.toggleCodeBlock({ language: 'javascript' })
       */
      toggleHtmlCodeBlock: (attributes?: { language: string }) => ReturnType;
      updateHtmlCodeBlock: (
        attrs: Partial<HtmlCodeBlockAttributes>
      ) => ReturnType;
    };
  }
}

export const HTMLCodeBlockExtension = CodeBlockLowlight.extend({
  name: 'htmlCodeBlock',
  content: '(text|variable)*',

  addAttributes() {
    return {
      ...this.parent?.(),
      activeTab: 'code',
      showIfKey: {
        default: DEFAULT_SECTION_SHOW_IF_KEY,
        parseHTML: (element) => {
          return (
            element.getAttribute('data-show-if-key') ||
            DEFAULT_SECTION_SHOW_IF_KEY
          );
        },
        renderHTML(attributes) {
          if (!attributes.showIfKey) {
            return {};
          }

          return {
            'data-show-if-key': attributes.showIfKey,
          };
        },
      },
    };
  },

  addNodeView() {
    return ReactNodeViewRenderer(HTMLCodeBlockView, {
      className: 'relative',
      attrs: ({ node }) => ({
        'data-active-tab': node?.attrs?.activeTab || 'code',
      }),
    });
  },

  addCommands() {
    return {
      setHtmlCodeBlock:
        (attributes) =>
        ({ commands }) => {
          return commands.setNode(this.name, attributes);
        },
      toggleHtmlCodeBlock:
        (attributes) =>
        ({ commands }) => {
          return commands.toggleNode(this.name, 'paragraph', attributes);
        },
      updateHtmlCodeBlock: (attrs) => updateAttributes(this.name, attrs),
    };
  },

  addKeyboardShortcuts() {
    return {
      ...this.parent?.(),
      'Mod-a': ({ editor }) => {
        const { selection } = editor.state;
        const $pos = selection.$anchor;

        // resolve the position to the code block node
        // and check if the node is a code block
        const node = $pos.node($pos.depth);
        if (node.type.name !== this.name) {
          return false;
        }

        // find the depth of the code block node
        // to get the correct start and end position
        // usually when we are inside a code block
        // the depth is the same as the code block node
        let depth = $pos.depth;
        for (let d = depth; d > 0; d--) {
          if ($pos.node(d).type.name === this.name) {
            depth = d;
            break;
          }
        }

        // find the start and end position of the code block
        // and set the selection to the code block
        const start = $pos.before(depth) + 1; // +1 to move inside the code block
        const end = $pos.after(depth) - 1; // -1 to stay inside the code block

        const from = editor.state.doc.resolve(start);
        const to = editor.state.doc.resolve(end);
        if (from && to) {
          const transaction = editor.state.tr.setSelection(
            TextSelection.between(from, to)
          );
          editor.view.dispatch(transaction);
          return true;
        }

        return false;
      },
    };
  },
}).configure({
  lowlight,
});

import { IconPlaceholder } from "@/components/icon-placeholder"
import { ImageOffIcon } from "lucide-react"
import {
  type CSSProperties,
  useCallback,
  useEffect,
  useRef,
  useState,
} from 'react';
import { type NodeViewProps, NodeViewWrapper } from '@tiptap/react';
import { useImageUploadOptions } from '../../extensions/image-upload/image-upload';
import { cn } from '@/lib/utils';
import { useEvent } from '../../utils/use-event';
import { getAspectRatio, getNewHeight } from '../../utils/aspect-ratio';

const MIN_WIDTH = 20;
export const IMAGE_MAX_WIDTH = 600;
export const IMAGE_MAX_HEIGHT = 400;

export type ImageStatus = 'idle' | 'loading' | 'loaded' | 'error';

export function ImageView(props: NodeViewProps) {
  const { node, updateAttributes, selected, editor } = props;

  const [status, setStatus] = useState<ImageStatus>('idle');
  const [isPlaceholderImage, setIsPlaceholderImage] = useState(false);

  const { onImageUpload, allowedMimeTypes = [] } =
    useImageUploadOptions(editor);

  const wrapperRef = useRef<HTMLDivElement>(null);
  const imgRef = useRef<HTMLImageElement>(null);

  const [resizingStyle, setResizingStyle] = useState<
    Pick<CSSProperties, 'width' | 'height'> | undefined
  >();

  const [isDraggingOver, setIsDraggingOver] = useState(false);

  const handleMouseDown = useEvent(
    (event: React.MouseEvent<HTMLDivElement>) => {
      const imageParent = document.querySelector(
        '.ProseMirror-selectednode'
      ) as HTMLDivElement;

      if (!imgRef.current || !imageParent || !selected) {
        return;
      }

      const imageParentWidth = Math.max(
        imageParent.offsetWidth,
        IMAGE_MAX_WIDTH
      );

      event.preventDefault();
      const direction = event.currentTarget.dataset.direction || '--';
      const initialXPosition = event.clientX;
      const initialYPosition = event.clientY;
      const currentWidth = imgRef.current.width;
      const currentHeight = imgRef.current.height;
      let newWidth = currentWidth;
      let newHeight = currentHeight;
      const transformX = direction[1] === 'w' ? -1 : 1;
      const transformY = direction[0] === 'n' ? -1 : 1;

      const removeListeners = () => {
        window.removeEventListener('mousemove', mouseMoveHandler);
        window.removeEventListener('mouseup', removeListeners);
        const aspectRatio = getAspectRatio(newWidth, newHeight);
        updateAttributes({ width: newWidth, height: newHeight, aspectRatio });
        setResizingStyle(undefined);
      };

      const mouseMoveHandler = (event: MouseEvent) => {
        newWidth = Math.max(
          currentWidth + transformX * (event.clientX - initialXPosition),
          MIN_WIDTH
        );
        newHeight = Math.max(
          currentHeight + transformY * (event.clientY - initialYPosition),
          MIN_WIDTH
        );

        if (newWidth > imageParentWidth) {
          newWidth = imageParentWidth;
        }
        if (newHeight > IMAGE_MAX_HEIGHT) {
          newHeight = IMAGE_MAX_HEIGHT;
        }

        // If aspect ratio is locked, calculate height based on aspect ratio
        if (node.attrs.lockAspectRatio) {
          const aspectRatio =
            node.attrs.aspectRatio &&
            isFinite(node.attrs.aspectRatio) &&
            node.attrs.aspectRatio > 0
              ? node.attrs.aspectRatio
              : currentWidth / currentHeight;
          newHeight = getNewHeight(newWidth, aspectRatio);
        }

        setResizingStyle({ width: newWidth, height: newHeight });
        // If mouse is up, remove event listeners
        if (!event.buttons) {
          return removeListeners();
        }
      };

      window.addEventListener('mousemove', mouseMoveHandler);
      window.addEventListener('mouseup', removeListeners);
    }
  );

  const dragCornerButton = useCallback(
    (direction: string) => {
      if (isPlaceholderImage) {
        return null;
      }

      return (
        <div
          role="button"
          tabIndex={0}
          onMouseDown={handleMouseDown}
          data-direction={direction}
          className="bg-rose-500"
          style={{
            position: 'absolute',
            height: '10px',
            width: '10px',
            ...{ n: { top: 0 }, s: { bottom: 0 } }[direction[0]],
            ...{ w: { left: 0 }, e: { right: 0 } }[direction[1]],
            cursor: `${direction}-resize`,
          }}
        />
      );
    },
    [handleMouseDown, isPlaceholderImage]
  );

  let {
    alignment = 'center',
    width,
    height,
    src,
    borderRadius,
  } = node.attrs || {};

  const {
    externalLink,
    isExternalLinkVariable,
    isSrcVariable,
    showIfKey,
    aspectRatio: defaultAspectRatio,
    borderRadius: _,
    lockAspectRatio,
    ...attrs
  } = node.attrs || {};

  const hasImageSrc = !!attrs.src;
  const isDroppable =
    !!onImageUpload &&
    editor.isEditable &&
    !hasImageSrc &&
    !isSrcVariable &&
    status === 'idle';

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!isDroppable || !e.target.files || e.target.files.length === 0) {
      return;
    }

    const file = e.target.files[0];
    await handleImageUpload(file);
  };

  const handleImageUpload = useCallback(
    async (file: File) => {
      if (!isDroppable) {
        return;
      }

      try {
        setStatus('loading');
        const imageUrl = await onImageUpload(file);
        updateAttributes({ src: imageUrl });
        setIsPlaceholderImage(false);
        setStatus('loaded');
      } catch (error) {
        console.error('Error uploading image:', error);
        setStatus('error');
      }
    },
    [onImageUpload, updateAttributes]
  );

  // load the image using new Image() to avoid layout shift
  // then if the image is loaded, set the status to loaded
  useEffect(() => {
    if (!src || isSrcVariable) {
      return;
    }

    setStatus('loading');
    const isPlaceHolder =
      editor?.extensionStorage?.imageUpload?.placeholderImages?.has(src) ??
      false;
    setIsPlaceholderImage(isPlaceHolder);
    const img = new Image();
    img.src = src;
    img.onload = () => {
      setStatus('loaded');
      // for some reason Apple Mail doesn't respect the width and height attributes
      // update the dimensions to ensure that the image is not stretched
      const { naturalWidth, naturalHeight } = img;
      const wrapper = wrapperRef?.current;

      if (!wrapper || width !== 'auto' || !naturalWidth) {
        return;
      }

      const wrapperWidth = wrapper.offsetWidth;
      const aspectRatio = getAspectRatio(naturalWidth, naturalHeight);
      const calculatedHeight = Math.min(
        getNewHeight(wrapperWidth, aspectRatio),
        naturalHeight
      );

      updateAttributes({
        width: Math.min(wrapperWidth, naturalWidth),
        height: Math.min(calculatedHeight, naturalHeight),
        aspectRatio,
      });
    };
    img.onerror = () => {
      setStatus('error');
    };

    return () => {
      img.src = '';
      img.onload = null;
      img.onerror = null;
    };
  }, [src]);

  const handleDragOver = useCallback(
    (e: React.DragEvent) => {
      if (!isDroppable) {
        return;
      }

      e.preventDefault();
      e.stopPropagation();
      setIsDraggingOver(true);
    },
    [onImageUpload]
  );

  const handleDragLeave = useCallback(
    (e: React.DragEvent) => {
      if (!isDroppable) {
        return;
      }

      e.preventDefault();
      e.stopPropagation();
      setIsDraggingOver(false);
    },
    [onImageUpload]
  );

  const handleDrop = useCallback(
    async (e: React.DragEvent) => {
      if (!isDroppable) {
        return;
      }

      e.preventDefault();
      e.stopPropagation();
      setIsDraggingOver(false);
      const files = e.dataTransfer?.files;
      if (!files || files?.length === 0) {
        return;
      }

      const firstFile = files[0];
      if (!allowedMimeTypes.includes(firstFile.type)) {
        return;
      }

      await handleImageUpload(firstFile);
    },
    [handleImageUpload]
  );

  return (
    <NodeViewWrapper
      as="div"
      draggable={editor.isEditable}
      data-drag-handle={editor.isEditable}
      className={cn(
        "mly-image-drop-zone relative after:pointer-events-none after:absolute after:inset-0 after:rounded after:border-2 after:border-dashed after:border-[#00bcff] after:opacity-0 after:transition-opacity after:duration-200 after:content-['']",
        isDraggingOver && 'mly-drag-over after:opacity-100'
      )}
      style={{
        ...(hasImageSrc && status === 'loaded'
          ? {
              width: width && width !== 'auto' ? `${width}px` : undefined,
              height: height && height !== 'auto' ? `${height}px` : undefined,
              ...resizingStyle,
            }
          : {}),
        overflow: 'hidden',
        position: 'relative',
        // Weird! Basically tiptap/prose wraps this in a span and the line height causes an annoying buffer.
        lineHeight: '0px',
        display: 'block',
        maxWidth: '100%',
        ...({
          center: { marginLeft: 'auto', marginRight: 'auto' },
          left: { marginRight: 'auto' },
          right: { marginLeft: 'auto' },
        }[alignment as string] || {}),
      }}
      ref={wrapperRef}
      {...(isDroppable
        ? {
            onDragOver: handleDragOver,
            onDragLeave: handleDragLeave,
            onDrop: handleDrop,
          }
        : {})}
    >
      {!hasImageSrc && status === 'idle' && (
        <ImageStatusLabel
          status="idle"
          minHeight={height}
          isDropZone={isDroppable}
        />
      )}

      {!hasImageSrc && status === 'loading' && !isSrcVariable && (
        <ImageStatusLabel status="loading" minHeight={height} />
      )}

      {hasImageSrc && isSrcVariable && (
        <ImageStatusLabel status="variable" minHeight={height} />
      )}

      {hasImageSrc && status === 'loading' && !isSrcVariable && (
        <ImageStatusLabel status="loading" minHeight={height} />
      )}
      {hasImageSrc && status === 'error' && !isSrcVariable && (
        <ImageStatusLabel status="error" minHeight={height} />
      )}

      {isDroppable && (
        <input
          type="file"
          accept="image/*"
          onChange={handleFileChange}
          className="absolute inset-0 opacity-0"
          multiple={false}
        />
      )}

      {hasImageSrc && status === 'loaded' && !isSrcVariable && (
        <>
          <img
            {...attrs}
            ref={imgRef}
            style={{
              ...resizingStyle,
              cursor: 'default',
              objectFit: 'fill',
              marginBottom: 0,
              borderRadius,
              width: resizingStyle?.width
                ? `${resizingStyle.width}px`
                : width && width !== 'auto'
                  ? `${width}px`
                  : 'auto',
              height: resizingStyle?.height
                ? `${resizingStyle.height}px`
                : height && height !== 'auto'
                  ? `${height}px`
                  : 'auto',
            }}
            draggable={editor.isEditable}
            className={cn(isPlaceholderImage && 'animate-pulse opacity-40')}
          />

          {selected && editor.isEditable && !isPlaceholderImage && (
            <>
              {/* Don't use a simple border as it pushes other content around. */}
              {[
                { left: 0, top: 0, height: '100%', width: '1px' },
                { right: 0, top: 0, height: '100%', width: '1px' },
                { top: 0, left: 0, width: '100%', height: '1px' },
                { bottom: 0, left: 0, width: '100%', height: '1px' },
              ].map((style, i) => (
                <div
                  key={i}
                  className="bg-rose-500"
                  style={{
                    position: 'absolute',
                    ...style,
                  }}
                />
              ))}
              {dragCornerButton('nw')}
              {dragCornerButton('ne')}
              {dragCornerButton('sw')}
              {dragCornerButton('se')}
            </>
          )}
        </>
      )}
    </NodeViewWrapper>
  );
}

type ImageStatusLabelProps = {
  status: ImageStatus | 'variable';
  minHeight?: number | string;
  isDropZone?: boolean;
} & React.HTMLAttributes<HTMLDivElement>;

export function ImageStatusLabel(props: ImageStatusLabelProps) {
  const { status, minHeight, className, style, isDropZone, ...rest } = props;

  return (
    <div
      {...rest}
      className={cn(
        'bg-muted flex items-center justify-center gap-2 rounded-lg px-4 py-2 text-sm font-medium',
        {
          'text-muted-foreground hover:bg-muted/60': status === 'loading',
          'text-destructive hover:bg-muted/60': status === 'error',
        },
        className
      )}
      style={{
        ...(minHeight
          ? {
              minHeight,
            }
          : {}),
        ...style,
      }}
    >
      {status === 'idle' && !isDropZone && (
        <>
          <ImageOffIcon className="size-4 stroke-[2.5]" />
          <span>No image selected</span>
        </>
      )}

      {status === 'idle' && isDropZone && (
        <>
          <IconPlaceholder
  lucide="GrabIcon"
  tabler="IconHandMove"
  hugeicons="HandGrabIcon"
  phosphor="HandGrabbing"
  remixicon="RiDragMove2Line"
  className="size-4 stroke-[2.5]"
/>
          <span>Click or Drop image here</span>
        </>
      )}

      {status === 'loading' && (
        <>
          <IconPlaceholder
  lucide="Loader2"
  tabler="IconLoader2"
  hugeicons="Loading03Icon"
  phosphor="CircleNotch"
  remixicon="RiLoader2Line"
  className="size-4 animate-spin stroke-[2.5]"
/>
          <span>Loading image...</span>
        </>
      )}
      {status === 'error' && (
        <>
          <IconPlaceholder
  lucide="Ban"
  tabler="IconBan"
  hugeicons="Cancel01Icon"
  phosphor="Prohibit"
  remixicon="RiForbidLine"
  className="size-4 stroke-[2.5]"
/>
          <span>Error loading image</span>
        </>
      )}
      {status === 'variable' && (
        <>
          <IconPlaceholder
  lucide="BracesIcon"
  tabler="IconBraces"
  hugeicons="BracesIcon"
  phosphor="BracketsCurly"
  remixicon="RiBracesLine"
  className="size-4 stroke-[2.5]"
/>
          <span>Variable Image URL</span>
        </>
      )}
    </div>
  );
}

import TiptapImage from '@tiptap/extension-image';
import { ReactNodeViewRenderer } from '@tiptap/react';
import { DEFAULT_SECTION_SHOW_IF_KEY } from '../section/section';
import { ImageView } from './image-view';

const DEFAULT_IMAGE_BORDER_RADIUS = 0;

export const ImageExtension = TiptapImage.extend({
  addAttributes() {
    return {
      ...this.parent?.(),
      width: {
        default: 'auto',
        parseHTML: (element) => {
          return (
            element.getAttribute('width') ||
            (element.style?.width || element.style?.inlineSize)?.replace(
              'px',
              ''
            ) ||
            null
          );
        },
        renderHTML: ({ width }) => ({ width }),
      },
      height: {
        default: 'auto',
        parseHTML: (element) => {
          return (
            element.getAttribute('height') ||
            (element.style?.height || element.style?.blockSize)?.replace(
              'px',
              ''
            ) ||
            null
          );
        },
        renderHTML: ({ height }) => ({ height }),
      },
      alignment: {
        default: 'center',
        renderHTML: ({ alignment }) => ({ 'data-alignment': alignment }),
        parseHTML: (element) =>
          element.getAttribute('data-alignment') || 'center',
      },

      externalLink: {
        default: null,
        renderHTML: ({ externalLink }) => {
          if (!externalLink) {
            return {};
          }
          return {
            'data-external-link': externalLink,
          };
        },
        parseHTML: (element) => {
          const externalLink = element.getAttribute('data-external-link');
          return externalLink ? { externalLink } : null;
        },
      },

      // Later we will remove this attribute
      // and use the `externalLink` attribute instead
      // when implement the URL variable feature
      isExternalLinkVariable: {
        default: false,
        parseHTML: (element) => {
          return (
            element.getAttribute('data-is-external-link-variable') === 'true'
          );
        },
        renderHTML: (attributes) => {
          if (!attributes.isExternalLinkVariable) {
            return {};
          }

          return {
            'data-is-external-link-variable': 'true',
          };
        },
      },

      borderRadius: {
        default: DEFAULT_IMAGE_BORDER_RADIUS,
        parseHTML: (element) => {
          return Number(element.getAttribute('data-border-radius'));
        },
        renderHTML: (attributes) => {
          return {
            'data-border-radius': attributes.borderRadius,
          };
        },
      },

      // Later we will remove this attribute
      // and use the `src` attribute instead when implement
      // the URL variable feature
      isSrcVariable: {
        default: false,
        parseHTML: (element) => {
          return element.getAttribute('data-is-src-variable') === 'true';
        },
        renderHTML: (attributes) => {
          if (!attributes.isSrcVariable) {
            return {};
          }

          return {
            'data-is-src-variable': 'true',
          };
        },
      },

      aspectRatio: {
        default: null,
        parseHTML: (element) => {
          return element.getAttribute('data-aspect-ratio') || null;
        },
        renderHTML: (attributes) => {
          if (!attributes?.aspectRatio) {
            return {};
          }

          return {
            'data-aspect-ratio': attributes?.aspectRatio,
          };
        },
      },

      lockAspectRatio: {
        default: true,
        parseHTML: (element) => {
          return element.getAttribute('data-lock-aspect-ratio') === 'true';
        },
        renderHTML: (attributes) => {
          if (!attributes.lockAspectRatio) {
            return {};
          }

          return {
            'data-lock-aspect-ratio': 'true',
          };
        },
      },

      showIfKey: {
        default: DEFAULT_SECTION_SHOW_IF_KEY,
        parseHTML: (element) => {
          return (
            element.getAttribute('data-show-if-key') ||
            DEFAULT_SECTION_SHOW_IF_KEY
          );
        },
        renderHTML(attributes) {
          if (!attributes.showIfKey) {
            return {};
          }

          return {
            'data-show-if-key': attributes.showIfKey,
          };
        },
      },
    };
  },
  addNodeView() {
    return ReactNodeViewRenderer(ImageView, {
      className: 'relative',
    });
  },
});

import { mergeAttributes, Node } from '@tiptap/core';
import { PluginKey, Plugin } from '@tiptap/pm/state';

export interface InlineImageOptions {
  /**
   * HTML attributes to add to the image element.
   * @default {}
   * @example { class: 'foo' }
   */
  HTMLAttributes: Record<string, any>;
}

export interface InlineImageAttributes {
  src: string;
  alt?: string;
  title?: string;
}

declare module '@tiptap/core' {
  interface Commands<ReturnType> {
    inlineImage: {
      setInlineImage: (options: InlineImageAttributes) => ReturnType;
    };
  }
}

export const DEFAULT_INLINE_IMAGE_HEIGHT = 20;
export const DEFAULT_INLINE_IMAGE_WIDTH = 20;

export const InlineImageExtension = Node.create<InlineImageOptions>({
  name: 'inlineImage',
  inline: true,
  group: 'inline',
  selectable: false,

  addOptions() {
    return {
      HTMLAttributes: {},
    };
  },

  addAttributes() {
    return {
      height: {
        default: DEFAULT_INLINE_IMAGE_HEIGHT,
      },
      width: {
        default: DEFAULT_INLINE_IMAGE_WIDTH,
      },

      src: {
        default: null,
      },
      isSrcVariable: {
        default: false,
        renderHTML(attributes) {
          if (!attributes.isSrcVariable) {
            return {};
          }

          return {
            'data-is-src-variable': 'true',
          };
        },
      },
      alt: {
        default: null,
      },
      title: {
        default: null,
      },

      externalLink: {
        default: null,
        renderHTML(attributes) {
          if (!attributes.externalLink) {
            return {};
          }

          return {
            'data-external-link': attributes.externalLink,
          };
        },
      },
      isExternalLinkVariable: {
        default: false,
        renderHTML(attributes) {
          if (!attributes.isExternalLinkVariable) {
            return {};
          }

          return {
            'data-is-external-link-variable': 'true',
          };
        },
      },
    };
  },

  parseHTML() {
    return [
      {
        tag: `img[data-type="${this.name}"]`,
      },
    ];
  },

  renderHTML({ HTMLAttributes }) {
    const attrs = mergeAttributes(this.options.HTMLAttributes, HTMLAttributes, {
      'data-type': this.name,
      class: 'relative',
      style: `display: inline; --mly-inline-image-height: ${HTMLAttributes.height}px; --mly-inline-image-width: ${HTMLAttributes.width}px; margin:0; vertical-align: middle;`,
      draggable: 'false',
      loading: 'lazy',
    });

    return ['img', attrs];
  },

  addCommands() {
    return {
      setInlineImage:
        (options) =>
        ({ commands }) => {
          return commands.insertContent({
            type: this.name,
            attrs: options,
          });
        },
    };
  },

  addProseMirrorPlugins() {
    return [
      new Plugin({
        key: new PluginKey('inlineImage'),
        props: {
          handleClickOn: (_, pos, node) => {
            if (node.type !== this.type) {
              return false;
            }

            const from = pos;
            const to = pos + node.nodeSize;

            this.editor.commands.setTextSelection({ from, to });
            return true;
          },
        },
      }),
    ];
  },
});

import { NodeViewProps, NodeViewWrapper } from '@tiptap/react';
import { Input } from '../components/input';
import { Popover, PopoverContent, PopoverTrigger } from '../components/popover';
import { Textarea } from '../components/textarea';
import { cn } from '@/lib/utils';

export function LinkCardComponent(props: NodeViewProps) {
  const { title, description, link, linkTitle, image, badgeText, subTitle } =
    props.node.attrs;
  const { getPos, editor } = props;

  return (
    <NodeViewWrapper
      className={`react-component ${
        props.selected && 'ProseMirror-selectednode'
      }`}
      draggable={editor.isEditable}
      data-drag-handle={editor.isEditable}
    >
      <Popover open={props.selected}>
        <PopoverTrigger asChild>
          <div
            tabIndex={-1}
            onClick={(e) => {
              e.preventDefault();
              const pos = getPos();
              editor.commands.setNodeSelection(pos);
            }}
          >
            <div className="no-prose border-border flex flex-col rounded-lg border">
              {image && (
                <div className="relative mb-1.5 w-full shrink-0">
                  <img
                    src={image}
                    alt="link-card"
                    className="no-prose mb-0! h-full w-full rounded-t-lg"
                    draggable={editor.isEditable}
                  />
                </div>
              )}
              <div className="flex items-stretch p-3">
                <div className={cn('flex flex-col')}>
                  <div className="!mb-1.5 flex items-center gap-1.5">
                    <h2 className="!mb-0 text-lg! font-semibold">{title}</h2>
                    {badgeText && (
                      <span className="!font-base rounded-md bg-yellow-200 px-2 py-1 text-xs leading-none font-semibold">
                        {badgeText}
                      </span>
                    )}{' '}
                    {subTitle && !badgeText && (
                      <span className="!font-base font-regular text-muted-foreground rounded-md text-xs leading-none">
                        {subTitle}
                      </span>
                    )}
                  </div>
                  <p className="text-muted-foreground !my-0 text-base!">
                    {description}{' '}
                    {linkTitle ? (
                      <a href={link} className="font-semibold">
                        {linkTitle}
                      </a>
                    ) : null}
                  </p>
                </div>
              </div>
            </div>
          </div>
        </PopoverTrigger>
        <PopoverContent
          align="end"
          className="flex w-96 flex-col gap-2"
          sideOffset={10}
          onOpenAutoFocus={(e) => e.preventDefault()}
          onCloseAutoFocus={(e) => e.preventDefault()}
        >
          <label className="w-full space-y-1">
            <span className="text-muted-foreground text-xs font-normal">
              Image
            </span>
            <Input
              placeholder="Add Image"
              type="url"
              value={image}
              onChange={(e) => {
                props.updateAttributes({
                  image: e.target.value,
                });
              }}
            />
          </label>

          <label className="w-full space-y-1">
            <span className="text-muted-foreground text-xs font-normal">
              Title
            </span>
            <Input
              placeholder="Add title"
              value={title}
              onChange={(e) => {
                props.updateAttributes({
                  title: e.target.value,
                });
              }}
            />
          </label>

          <label className="w-full space-y-1">
            <span className="text-muted-foreground text-xs font-normal">
              Description
            </span>
            <Textarea
              placeholder="Add description here"
              value={description}
              onChange={(e) => {
                props.updateAttributes({
                  description: e.target.value,
                });
              }}
            />
          </label>

          <div className="grid grid-cols-2 gap-2">
            <label className="w-full space-y-1">
              <span className="text-muted-foreground text-xs font-normal">
                Link Title
              </span>
              <Input
                placeholder="Add link title here"
                value={linkTitle}
                onChange={(e) => {
                  props.updateAttributes({
                    linkTitle: e.target.value,
                  });
                }}
              />
            </label>

            <label className="w-full space-y-1">
              <span className="text-muted-foreground text-xs font-normal">
                Link
              </span>
              <Input
                placeholder="Add link here"
                value={link}
                onChange={(e) => {
                  props.updateAttributes({
                    link: e.target.value,
                  });
                }}
              />
            </label>
          </div>

          <div className="grid grid-cols-2 gap-2">
            <label className="w-full space-y-1">
              <span className="text-muted-foreground text-xs font-normal">
                Badge Text
              </span>
              <Input
                placeholder="Add badge text here"
                value={badgeText}
                onChange={(e) => {
                  props.updateAttributes({
                    badgeText: e.target.value,
                  });
                }}
              />
            </label>

            <label className="w-full space-y-1">
              <span className="text-muted-foreground text-xs font-normal">
                Sub Title
              </span>
              <Input
                placeholder="Add sub title here"
                value={subTitle}
                onChange={(e) => {
                  props.updateAttributes({
                    subTitle: e.target.value,
                  });
                }}
              />
            </label>
          </div>
        </PopoverContent>
      </Popover>
    </NodeViewWrapper>
  );
}

import TiptapLink from '@tiptap/extension-link';

declare module '@tiptap/core' {
  interface Commands<ReturnType> {
    customLink: {
      setIsUrlVariable: (isUrlVariable: boolean) => ReturnType;
    };
  }
}

export const LinkExtension = TiptapLink.extend({
  addAttributes() {
    return {
      ...this.parent?.(),
      isUrlVariable: {
        default: false,
      },
    };
  },
  addCommands() {
    return {
      ...this.parent?.(),

      setIsUrlVariable:
        (isUrlVariable) =>
        ({ chain }) => {
          return chain().setMark('link', { isUrlVariable }).run();
        },
    };
  },
});

import { NodeViewProps } from '@tiptap/core';
import { NodeViewWrapper } from '@tiptap/react';
import { useCallback, useEffect } from 'react';
import { useState } from 'react';
import { LogoAttributes, logoSizes } from './logo';
import { ImageStatus, ImageStatusLabel } from '../image/image-view';
import { useImageUploadOptions } from '../../extensions/image-upload/image-upload';
import { cn } from '@/lib/utils';

export function LogoView(props: NodeViewProps) {
  const { node, editor, updateAttributes } = props;

  const [status, setStatus] = useState<ImageStatus>('idle');
  const [isPlaceholderImage, setIsPlaceholderImage] = useState(false);
  const [isDraggingOver, setIsDraggingOver] = useState(false);

  const { onImageUpload, allowedMimeTypes = [] } =
    useImageUploadOptions(editor);

  let {
    alignment = 'center',
    src: logoSrc,
    isSrcVariable,
    size = 'sm',
  } = (node.attrs || {}) as LogoAttributes;

  const hasImageSrc = !!logoSrc;
  const isDroppable =
    !!onImageUpload && editor.isEditable && !isSrcVariable && status === 'idle';

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!isDroppable || !e.target.files || e.target.files.length === 0) {
      return;
    }

    const file = e.target.files[0];
    await handleImageUpload(file);
  };

  const handleImageUpload = useCallback(
    async (file: File) => {
      if (!isDroppable) {
        return;
      }

      try {
        setStatus('loading');
        const imageUrl = await onImageUpload(file);
        updateAttributes({ src: imageUrl });
        setIsPlaceholderImage(false);
        setStatus('loaded');
      } catch (error) {
        console.error('Error uploading image:', error);
        setStatus('error');
      }
    },
    [onImageUpload, updateAttributes]
  );

  const handleDragOver = useCallback(
    (e: React.DragEvent) => {
      if (!isDroppable) {
        return;
      }

      e.preventDefault();
      e.stopPropagation();
      setIsDraggingOver(true);
    },
    [onImageUpload]
  );

  const handleDragLeave = useCallback(
    (e: React.DragEvent) => {
      if (!isDroppable) {
        return;
      }

      e.preventDefault();
      e.stopPropagation();
      setIsDraggingOver(false);
    },
    [onImageUpload]
  );

  const handleDrop = useCallback(
    async (e: React.DragEvent) => {
      if (!isDroppable) {
        return;
      }

      e.preventDefault();
      e.stopPropagation();
      setIsDraggingOver(false);
      const files = e.dataTransfer?.files;
      if (!files || files?.length === 0) {
        return;
      }

      const firstFile = files[0];
      if (!allowedMimeTypes.includes(firstFile.type)) {
        return;
      }

      await handleImageUpload(firstFile);
    },
    [handleImageUpload]
  );

  // load the image using new Image() to avoid layout shift
  // then if the image is loaded, set the status to loaded
  useEffect(() => {
    if (!logoSrc) {
      return;
    }

    setStatus('loading');
    const isPlaceHolder =
      editor?.extensionStorage?.imageUpload?.placeholderImages?.has(logoSrc) ??
      false;
    setIsPlaceholderImage(isPlaceHolder);
    const img = new Image();
    img.src = logoSrc;
    img.onload = () => {
      setStatus('loaded');
    };
    img.onerror = () => {
      setStatus('error');
    };

    return () => {
      img.src = '';
      img.onload = null;
      img.onerror = null;
    };
  }, [logoSrc]);

  const logoSize = logoSizes[size];

  return (
    <NodeViewWrapper
      as="div"
      draggable={editor.isEditable}
      data-drag-handle={editor.isEditable}
      style={{
        overflow: 'hidden',
        position: 'relative',
        // Weird! Basically tiptap/prose wraps this in a span and the line height causes an annoying buffer.
        lineHeight: '0px',
        display: 'block',
      }}
      className={cn(
        "mly-image-drop-zone after:pointer-events-none after:absolute after:inset-0 after:rounded after:border-2 after:border-dashed after:border-[#00bcff] after:opacity-0 after:transition-opacity after:duration-200 after:content-['']",
        isDraggingOver && 'mly-drag-over after:opacity-100'
      )}
      {...(isDroppable
        ? {
            onDragOver: handleDragOver,
            onDragLeave: handleDragLeave,
            onDrop: handleDrop,
          }
        : {})}
    >
      {!hasImageSrc && status === 'idle' && (
        <ImageStatusLabel
          status="idle"
          minHeight={logoSize}
          isDropZone={isDroppable}
        />
      )}

      {!hasImageSrc && status === 'loading' && !isSrcVariable && (
        <ImageStatusLabel status="loading" minHeight={logoSize} />
      )}

      {hasImageSrc && isSrcVariable && (
        <ImageStatusLabel status="variable" minHeight={logoSize} />
      )}
      {hasImageSrc && status === 'loading' && !isSrcVariable && (
        <ImageStatusLabel status="loading" minHeight={logoSize} />
      )}
      {hasImageSrc && status === 'error' && !isSrcVariable && (
        <ImageStatusLabel status="error" minHeight={logoSize} />
      )}

      {isDroppable && (
        <input
          type="file"
          accept="image/*"
          onChange={handleFileChange}
          className="absolute inset-0 opacity-0"
          multiple={false}
        />
      )}

      {hasImageSrc && status === 'loaded' && !isSrcVariable && (
        <img
          src={logoSrc}
          alt="Logo"
          style={{
            height: logoSize,
            width: logoSize,
            cursor: 'default',
            marginBottom: 0,
            ...({
              center: { marginLeft: 'auto', marginRight: 'auto' },
              left: { marginRight: 'auto' },
              right: { marginLeft: 'auto' },
            }[alignment] || {}),
          }}
          draggable={editor.isEditable}
        />
      )}
    </NodeViewWrapper>
  );
}

import TiptapImage from '@tiptap/extension-image';
import { ReactNodeViewRenderer } from '@tiptap/react';
import { DEFAULT_SECTION_SHOW_IF_KEY } from '../section/section';
import { LogoView } from './logo-view';

export const allowedLogoSize = ['sm', 'md', 'lg'] as const;
export type AllowedLogoSize = (typeof allowedLogoSize)[number];

export const allowedLogoAlignment = ['left', 'center', 'right'] as const;
export type AllowedLogoAlignment = (typeof allowedLogoAlignment)[number];

interface LogoOptions {
  src: string;
  alt?: string;
  title?: string;
  size?: AllowedLogoSize;
  alignment?: AllowedLogoAlignment;
}

export interface LogoAttributes {
  src?: string;
  size?: AllowedLogoSize;
  alignment?: AllowedLogoAlignment;

  showIfKey: string;
  isSrcVariable?: boolean;
}

declare module '@tiptap/core' {
  interface Commands<ReturnType> {
    logo: {
      setLogoImage: (options: LogoOptions) => ReturnType;
      setLogoAttributes: (attributes: Partial<LogoAttributes>) => ReturnType;
    };
  }
}

const DEFAULT_ALIGNMENT: AllowedLogoAlignment = 'left';
export const DEFAULT_LOGO_SIZE: AllowedLogoSize = 'sm';

export const logoSizes: Record<AllowedLogoSize, string> = {
  sm: '40px',
  md: '48px',
  lg: '64px',
};

export const LogoExtension = TiptapImage.extend({
  name: 'logo',
  priority: 1000,

  addAttributes() {
    return {
      ...this.parent?.(),
      'maily-component': {
        default: 'logo',
        renderHTML: (attributes) => {
          return {
            'data-maily-component': attributes['maily-component'],
          };
        },
        parseHTML: (element: Element) =>
          element.getAttribute('data-maily-component'),
      },
      size: {
        default: DEFAULT_LOGO_SIZE,
        parseHTML: (element) =>
          element.getAttribute('data-size') as AllowedLogoSize,
        renderHTML: (attributes) => {
          return {
            'data-size': attributes.size,
          };
        },
      },
      alignment: {
        default: DEFAULT_ALIGNMENT,
        parseHTML: (element) =>
          element.getAttribute('data-alignment') as AllowedLogoAlignment,
        renderHTML: (attributes) => {
          return {
            'data-alignment': attributes.alignment,
          };
        },
      },
      showIfKey: {
        default: DEFAULT_SECTION_SHOW_IF_KEY,
        parseHTML: (element) => {
          return (
            element.getAttribute('data-show-if-key') ||
            DEFAULT_SECTION_SHOW_IF_KEY
          );
        },
        renderHTML(attributes) {
          if (!attributes.showIfKey) {
            return {};
          }

          return {
            'data-show-if-key': attributes.showIfKey,
          };
        },
      },

      // Later we will remove this attribute
      // and use the `src` attribute instead when implement
      // the URL variable feature
      isSrcVariable: {
        default: false,
        parseHTML: (element) => {
          return element.getAttribute('data-is-src-variable') === 'true';
        },
        renderHTML: (attributes) => {
          if (!attributes.isSrcVariable) {
            return {};
          }

          return {
            'data-is-src-variable': 'true',
          };
        },
      },
    };
  },
  addCommands() {
    return {
      setLogoImage:
        (options) =>
        ({ commands }) => {
          return commands.insertContent({
            type: this.name,
            attrs: options,
          });
        },
      setLogoAttributes:
        (attributes) =>
        ({ commands }) => {
          return commands.updateAttributes('logo', attributes);
        },
    };
  },
  parseHTML() {
    return [
      {
        tag: `img[data-maily-component="${this.name}"]`,
      },
    ];
  },
  addNodeView() {
    return ReactNodeViewRenderer(LogoView, {
      className: 'relative',
    });
  },
});

import { Command } from '@tiptap/core';
import TiptapParagraph from '@tiptap/extension-paragraph';
import { DEFAULT_SECTION_SHOW_IF_KEY } from '../section/section';

export const allowedTextDirection = ['ltr', 'rtl'] as const;
export type AllowedTextDirection = (typeof allowedTextDirection)[number];
export const DEFAULT_TEXT_DIRECTION: AllowedTextDirection = 'ltr';

declare module '@tiptap/core' {
  interface Commands<ReturnType> {
    textDirection: {
      setTextDirection: (direction: AllowedTextDirection) => ReturnType;
    };
  }
}

export const ParagraphExtension = TiptapParagraph.extend({
  addAttributes() {
    return {
      ...(this?.parent?.() || {}),
      textDirection: {
        default: DEFAULT_TEXT_DIRECTION,
        parseHTML: (element) => {
          return (
            element.getAttribute('data-text-direction') ||
            element.getAttribute('dir') ||
            DEFAULT_TEXT_DIRECTION
          );
        },
        renderHTML(attributes) {
          if (
            !attributes.textDirection ||
            attributes.textDirection === DEFAULT_TEXT_DIRECTION
          ) {
            return {};
          }

          return {
            'data-text-direction': attributes.textDirection,
            dir: attributes.textDirection,
          };
        },
      },
      showIfKey: {
        default: DEFAULT_SECTION_SHOW_IF_KEY,
        parseHTML: (element) => {
          return (
            element.getAttribute('data-show-if-key') ||
            DEFAULT_SECTION_SHOW_IF_KEY
          );
        },
        renderHTML(attributes) {
          if (!attributes.showIfKey) {
            return {};
          }

          return {
            'data-show-if-key': attributes.showIfKey,
          };
        },
      },
    };
  },

  addCommands() {
    return {
      ...this.parent?.(),
      setTextDirection:
        (direction: AllowedTextDirection): Command =>
        ({ commands }) => {
          return commands.updateAttributes(this.name, {
            textDirection: direction,
          });
        },
    };
  },
});

