import { mergeAttributes, Node } from '@tiptap/core';
import { ReactNodeViewRenderer } from '@tiptap/react';
import { RepeatView } from './repeat-view';
import { updateAttributes } from '../../utils/update-attribute';
import { DEFAULT_SECTION_SHOW_IF_KEY } from '../section/section';

type RepeatAttributes = {
  each: string;
  isUpdatingKey: boolean;
  showIfKey: string;
};

declare module '@tiptap/core' {
  interface Commands<ReturnType> {
    repeat: {
      setRepeat: () => ReturnType;
      updateRepeat: (attrs: Partial<RepeatAttributes>) => ReturnType;
    };
  }
}

export const RepeatExtension = Node.create({
  name: 'repeat',
  group: 'block',
  content: '(block|columns)+',
  draggable: true,
  isolating: true,

  addAttributes() {
    return {
      each: {
        default: 'items',
        parseHTML: (element) => {
          return element.getAttribute('each') || '';
        },
        renderHTML: (attributes) => {
          if (!attributes.each) {
            return {};
          }

          return {
            each: attributes.each,
          };
        },
      },
      isUpdatingKey: {
        default: false,
      },
      showIfKey: {
        default: DEFAULT_SECTION_SHOW_IF_KEY,
        parseHTML: (element) => {
          return (
            element.getAttribute('data-show-if-key') ||
            DEFAULT_SECTION_SHOW_IF_KEY
          );
        },
        renderHTML(attributes) {
          if (!attributes.showIfKey) {
            return {};
          }

          return {
            'data-show-if-key': attributes.showIfKey,
          };
        },
      },
    };
  },

  parseHTML() {
    return [
      {
        tag: `div[data-type="${this.name}"]`,
      },
    ];
  },

  renderHTML({ HTMLAttributes }) {
    return [
      'div',
      mergeAttributes(HTMLAttributes, {
        'data-type': this.name,
      }),
      0,
    ];
  },

  addCommands() {
    return {
      setRepeat:
        () =>
        ({ commands }) => {
          return commands.insertContent({
            type: this.name,
            attrs: {},
            content: [
              {
                type: 'paragraph',
              },
            ],
          });
        },
      updateRepeat: (attrs) => updateAttributes(this.name, attrs),
    };
  },

  addNodeView() {
    return ReactNodeViewRenderer(RepeatView, {
      contentDOMElementTag: 'div',
      className: 'relative',
    });
  },
});

import { updateAttributes } from '../../utils/update-attribute';
import { mergeAttributes, Node } from '@tiptap/core';

export const DEFAULT_SECTION_BACKGROUND_COLOR = '#f7f7f7';
export const DEFAULT_SECTION_ALIGN = 'left';
export const DEFAULT_SECTION_BORDER_WIDTH = 2;
export const DEFAULT_SECTION_BORDER_COLOR = '#e2e2e2';
export const DEFAULT_SECTION_BORDER_RADIUS = 0;

export const DEFAULT_SECTION_MARGIN_TOP = 0;
export const DEFAULT_SECTION_MARGIN_RIGHT = 0;
export const DEFAULT_SECTION_MARGIN_BOTTOM = 0;
export const DEFAULT_SECTION_MARGIN_LEFT = 0;

export const DEFAULT_SECTION_PADDING_TOP = 0;
export const DEFAULT_SECTION_PADDING_RIGHT = 0;
export const DEFAULT_SECTION_PADDING_BOTTOM = 0;
export const DEFAULT_SECTION_PADDING_LEFT = 0;

export const DEFAULT_SECTION_SHOW_IF_KEY = null;

type SectionAttributes = {
  borderRadius: number;
  backgroundColor: string;
  align: string;
  borderWidth: number;
  borderColor: string;

  marginTop: number;
  marginRight: number;
  marginBottom: number;
  marginLeft: number;

  paddingTop: number;
  paddingRight: number;
  paddingBottom: number;
  paddingLeft: number;

  showIfKey: string | null;
};

declare module '@tiptap/core' {
  interface Commands<ReturnType> {
    section: {
      setSection: () => ReturnType;
      updateSection: (attrs: Partial<SectionAttributes>) => ReturnType;
    };
  }
}

export const SectionExtension = Node.create({
  name: 'section',
  group: 'block',
  content: '(block|columns)+',
  defining: true,
  isolating: true,

  addAttributes() {
    return {
      borderRadius: {
        default: 0,
        parseHTML: (element) => {
          return Number(element?.style?.borderRadius?.replace(/['"]+/g, ''));
        },
        renderHTML: (attributes) => {
          if (!attributes.borderRadius) {
            return {};
          }

          return {
            style: `border-radius: ${attributes.borderRadius}px`,
          };
        },
      },
      backgroundColor: {
        default: DEFAULT_SECTION_BACKGROUND_COLOR,
        parseHTML: (element) => {
          return element.style.backgroundColor;
        },
        renderHTML: (attributes) => {
          if (!attributes.backgroundColor) {
            return {};
          }

          return {
            style: `background-color: ${attributes.backgroundColor};--bg-color: ${attributes.backgroundColor}`,
          };
        },
      },
      align: {
        default: DEFAULT_SECTION_ALIGN,
        parseHTML: (element) => {
          return element.getAttribute('align') || DEFAULT_SECTION_ALIGN;
        },
        renderHTML(attributes) {
          if (!attributes.align) {
            return {};
          }

          return {
            align: attributes.align,
          };
        },
      },
      borderWidth: {
        default: DEFAULT_SECTION_BORDER_WIDTH,
        parseHTML: (element) => {
          return (
            Number(element?.style?.borderWidth?.replace(/['"]+/g, '')) || 0
          );
        },
        renderHTML: (attributes) => {
          if (!attributes.borderWidth) {
            return {};
          }

          return {
            style: `border-width: ${attributes.borderWidth}px`,
          };
        },
      },
      borderColor: {
        default: DEFAULT_SECTION_BORDER_COLOR,
        parseHTML: (element) => {
          return element.style.borderColor;
        },
        renderHTML: (attributes) => {
          if (!attributes.borderColor) {
            return {};
          }

          return {
            style: `border-color: ${attributes.borderColor}`,
          };
        },
      },
      paddingTop: {
        default: DEFAULT_SECTION_PADDING_TOP,
        parseHTML: (element) => {
          return Number(element?.style?.paddingTop?.replace(/['"]+/g, '')) || 0;
        },
        renderHTML: (attributes) => {
          if (!attributes.paddingTop) {
            return {};
          }

          return {
            style: `padding-top: ${attributes.paddingTop}px`,
          };
        },
      },
      paddingRight: {
        default: DEFAULT_SECTION_PADDING_RIGHT,
        parseHTML: (element) =>
          Number(element?.style?.paddingRight?.replace(/['"]+/g, '')) || 0,
        renderHTML: (attributes) => {
          if (!attributes.paddingRight) {
            return {};
          }

          return {
            style: `padding-right: ${attributes.paddingRight}px`,
          };
        },
      },
      paddingBottom: {
        default: DEFAULT_SECTION_PADDING_BOTTOM,
        parseHTML: (element) =>
          Number(element?.style?.paddingBottom?.replace(/['"]+/g, '')) || 0,
        renderHTML: (attributes) => {
          if (!attributes.paddingBottom) {
            return {};
          }

          return {
            style: `padding-bottom: ${attributes.paddingBottom}px`,
          };
        },
      },
      paddingLeft: {
        default: DEFAULT_SECTION_PADDING_LEFT,
        parseHTML: (element) =>
          Number(element?.style?.paddingLeft?.replace(/['"]+/g, '')) || 0,
        renderHTML: (attributes) => {
          if (!attributes.paddingLeft) {
            return {};
          }

          return {
            style: `padding-left: ${attributes.paddingLeft}px`,
          };
        },
      },
      marginTop: {
        default: DEFAULT_SECTION_MARGIN_TOP,
        parseHTML: (element) => {
          return Number(element?.style?.marginTop?.replace(/['"]+/g, '')) || 0;
        },
        renderHTML: (attributes) => {
          if (!attributes.marginTop) {
            return {};
          }

          return {
            marginTop: attributes.marginTop,
          };
        },
      },
      marginRight: {
        default: DEFAULT_SECTION_MARGIN_RIGHT,
        parseHTML: (element) =>
          Number(element?.style?.marginRight?.replace(/['"]+/g, '')) || 0,
        renderHTML: (attributes) => {
          if (!attributes.marginRight) {
            return {};
          }

          return {
            marginRight: attributes.marginRight,
          };
        },
      },
      marginBottom: {
        default: DEFAULT_SECTION_MARGIN_BOTTOM,
        parseHTML: (element) =>
          Number(element?.style?.marginBottom?.replace(/['"]+/g, '')) || 0,
        renderHTML: (attributes) => {
          if (!attributes.marginBottom) {
            return {};
          }

          return {
            marginBottom: attributes.marginBottom,
          };
        },
      },
      marginLeft: {
        default: DEFAULT_SECTION_MARGIN_LEFT,
        parseHTML: (element) =>
          Number(element?.style?.marginLeft?.replace(/['"]+/g, '')) || 0,
        renderHTML: (attributes) => {
          if (!attributes.marginLeft) {
            return {};
          }

          return {
            marginLeft: attributes.marginLeft,
          };
        },
      },

      showIfKey: {
        default: DEFAULT_SECTION_SHOW_IF_KEY,
        parseHTML: (element) => {
          return (
            element.getAttribute('data-show-if-key') ||
            DEFAULT_SECTION_SHOW_IF_KEY
          );
        },
        renderHTML(attributes) {
          if (!attributes.showIfKey) {
            return {};
          }

          return {
            'data-show-if-key': attributes.showIfKey,
          };
        },
      },
    };
  },

  addCommands() {
    return {
      setSection:
        () =>
        ({ commands }) => {
          return commands.insertContent({
            type: this.name,
            attrs: {
              type: this.name,
            },
            content: [
              {
                type: 'paragraph',
              },
            ],
          });
        },
      updateSection: (attrs) => updateAttributes(this.name, attrs),
    };
  },

  renderHTML({ HTMLAttributes }) {
    const {
      marginTop = 0,
      marginRight = 0,
      marginBottom = 0,
      marginLeft = 0,
    } = HTMLAttributes;

    return [
      'table',
      {
        'data-type': this.name,
        border: 0,
        cellpadding: 0,
        cellspacing: 0,
        class: 'w-full border-separate relative table-fixed m-0 p-0',
        style: `margin-top: ${marginTop}px; margin-right: ${marginRight}px; margin-bottom: ${marginBottom}px; margin-left: ${marginLeft}px;`,
      },
      [
        'tbody',
        {
          class: 'w-full',
        },
        [
          'tr',
          {
            class: 'w-full',
          },
          [
            'td',
            mergeAttributes(HTMLAttributes, {
              'data-type': 'section-cell',
              style: 'border-style: solid',
              class:
                'w-full [text-align:revert-layer] p-0 [&>*:first-child]:mt-0 [&>*:last-child]:mb-0',
            }),
            0,
          ],
        ],
      ],
    ];
  },

  parseHTML() {
    return [
      {
        tag: 'table[data-type="section"]',
      },
    ];
  },
});

import { mergeAttributes, Node } from '@tiptap/core';
import { DEFAULT_SECTION_SHOW_IF_KEY } from './section/section';

export interface SpacerOptions {
  height: number;
  showIfKey: string;
  HTMLAttributes: Record<string, any>;
}

declare module '@tiptap/core' {
  interface Commands<ReturnType> {
    spacer: {
      setSpacer: (options: { height: number }) => ReturnType;
      setSpacerSize: (height: number) => ReturnType;
      setSpacerShowIfKey: (showIfKey: string) => ReturnType;
      unsetSpacer: () => ReturnType;
    };
  }
}

export const DEFAULT_SPACER_HEIGHT = 8;

export const Spacer = Node.create<SpacerOptions>({
  name: 'spacer',
  priority: 1000,

  group: 'block',
  draggable: true,
  addAttributes() {
    return {
      height: {
        default: DEFAULT_SPACER_HEIGHT,
        parseHTML: (element) => Number(element.getAttribute('data-height')),
        renderHTML: (attributes) => {
          return {
            'data-height': attributes.height,
          };
        },
      },
      showIfKey: {
        default: DEFAULT_SECTION_SHOW_IF_KEY,
        parseHTML: (element) => {
          return (
            element.getAttribute('data-show-if-key') ||
            DEFAULT_SECTION_SHOW_IF_KEY
          );
        },
        renderHTML(attributes) {
          if (!attributes.showIfKey) {
            return {};
          }

          return {
            'data-show-if-key': attributes.showIfKey,
          };
        },
      },
    };
  },

  addCommands() {
    return {
      setSpacer:
        (options) =>
        ({ commands }) => {
          return commands.insertContent({
            type: this.name,
            attrs: {
              height: options.height,
            },
          });
        },

      setSpacerSize:
        (height) =>
        ({ commands }) => {
          return commands.updateAttributes('spacer', { height });
        },

      setSpacerShowIfKey:
        (showIfKey) =>
        ({ commands }) => {
          return commands.updateAttributes('spacer', { showIfKey });
        },

      unsetSpacer:
        () =>
        ({ commands }) => {
          return commands.deleteNode('spacer');
        },
    };
  },
  renderHTML({ HTMLAttributes, node }) {
    const { height } = node.attrs as SpacerOptions;

    return [
      'div',
      mergeAttributes(
        {
          'data-maily-component': this.name,
        },
        this.options.HTMLAttributes,
        HTMLAttributes,
        {
          class: 'spacer relative full z-50',
          contenteditable: false,
          style: `height: ${height}px;--spacer-height: ${height}px;`,
        }
      ),
    ];
  },
  parseHTML() {
    return [{ tag: `div[data-maily-component="${this.name}"]` }];
  },
});

import { IconPlaceholder } from "@/components/icon-placeholder"
import { cn } from '@/lib/utils';
import {
  forwardRef,
  useEffect,
  useImperativeHandle,
  useRef,
  useState,
} from 'react';
import { Variable } from './variable';

export type VariableSuggestionsPopoverProps = {
  items: Variable[];
  onSelectItem: (item: Variable) => void;
};

export type VariableSuggestionsPopoverRef = {
  moveUp: () => void;
  moveDown: () => void;
  select: () => void;
};

export type VariableSuggestionsPopoverType = React.ForwardRefExoticComponent<
  VariableSuggestionsPopoverProps &
    React.RefAttributes<VariableSuggestionsPopoverRef>
>;

export const VariableSuggestionsPopover: VariableSuggestionsPopoverType =
  forwardRef((props, ref) => {
    const { items, onSelectItem } = props;

    const [selectedIndex, setSelectedIndex] = useState(0);
    const scrollContainerRef = useRef<HTMLDivElement>(null);
    const itemRefs = useRef<(HTMLButtonElement | null)[]>([]);

    const scrollSelectedIntoView = (index: number) => {
      const container = scrollContainerRef.current;
      const selectedItem = itemRefs.current[index];

      if (!container || !selectedItem) {
        return;
      }

      const containerRect = container.getBoundingClientRect();
      const itemRect = selectedItem.getBoundingClientRect();

      const padding = 4;
      if (itemRect.bottom > containerRect.bottom) {
        container.scrollTop += itemRect.bottom - containerRect.bottom + padding;
      } else if (itemRect.top < containerRect.top) {
        container.scrollTop += itemRect.top - containerRect.top - padding;
      }
    };

    useEffect(() => {
      setSelectedIndex(0);
      if (scrollContainerRef.current) {
        scrollContainerRef.current.scrollTop = 0;
      }
      itemRefs.current = items.map(() => null);
    }, [items]);

    useEffect(() => {
      scrollSelectedIntoView(selectedIndex);
    }, [selectedIndex]);

    useImperativeHandle(ref, () => ({
      moveUp: () => {
        setSelectedIndex((selectedIndex + items.length - 1) % items.length);
      },
      moveDown: () => {
        setSelectedIndex((selectedIndex + 1) % items.length);
      },
      select: () => {
        const item = items[selectedIndex];
        if (!item) {
          return;
        }

        onSelectItem(item);
      },
    }));

    return (
      <div className="border-border bg-background z-50 w-64 rounded-lg border shadow-md transition-all">
        <div className="border-border bg-muted/40 text-muted-foreground flex items-center justify-between gap-2 border-b px-1 py-1.5">
          <span className="text-xs uppercase">Variables</span>
          <VariableIcon>
            <IconPlaceholder
  lucide="Braces"
  tabler="IconBraces"
  hugeicons="BracesIcon"
  phosphor="BracketsCurly"
  remixicon="RiBracesLine"
  className="size-3 stroke-[2.5]"
/>
          </VariableIcon>
        </div>

        <div ref={scrollContainerRef} className="max-h-52 overflow-y-auto">
          <div className="flex w-fit min-w-full flex-col gap-0.5 p-1">
            {items?.length ? (
              items?.map((item, index: number) => (
                <button
                  key={index}
                  ref={(el) => (itemRefs.current[index] = el)}
                  onClick={() => onSelectItem(item)}
                  className={cn(
                    'text-foreground hover:bg-muted flex w-fit min-w-full items-center gap-2 rounded-md px-2 py-1 text-left font-mono text-sm',
                    index === selectedIndex ? 'bg-muted' : 'bg-background'
                  )}
                >
                  <IconPlaceholder
  lucide="Braces"
  tabler="IconBraces"
  hugeicons="BracesIcon"
  phosphor="BracketsCurly"
  remixicon="RiBracesLine"
  className="size-3 stroke-[2.5] text-rose-600"
/>
                  {item?.label || item.name}
                </button>
              ))
            ) : (
              <div className="text-foreground hover:bg-muted flex h-7 w-full items-center gap-2 rounded-md px-2 py-1 text-left font-mono text-[13px]">
                No result
              </div>
            )}
          </div>
        </div>

        <div className="border-border text-muted-foreground flex items-center justify-between gap-2 border-t px-1 py-1.5">
          <div className="flex items-center gap-1">
            <VariableIcon>
              <IconPlaceholder
  lucide="ArrowDownIcon"
  tabler="IconArrowDown"
  hugeicons="ArrowDown01Icon"
  phosphor="ArrowDown"
  remixicon="RiArrowDownLine"
  className="size-3 stroke-[2.5]"
/>
            </VariableIcon>
            <VariableIcon>
              <IconPlaceholder
  lucide="ArrowUpIcon"
  tabler="IconArrowUp"
  hugeicons="ArrowUp01Icon"
  phosphor="ArrowUp"
  remixicon="RiArrowUpLine"
  className="size-3 stroke-[2.5]"
/>
            </VariableIcon>
            <span className="text-muted-foreground text-xs">Navigate</span>
          </div>
          <VariableIcon>
            <IconPlaceholder
  lucide="CornerDownLeftIcon"
  tabler="IconCornerDownLeft"
  hugeicons="CornerDownLeftIcon"
  phosphor="ArrowBendDownLeft"
  remixicon="RiCornerDownLeftLine"
  className="size-3 stroke-[2.5]"
/>
          </VariableIcon>
        </div>
      </div>
    );
  });

type VariableIconProps = {
  className?: string;
  children: React.ReactNode;
};

function VariableIcon(props: VariableIconProps) {
  const { className, children } = props;

  return (
    <div
      className={cn(
        'border-border flex size-5 items-center justify-center rounded-md border',
        className
      )}
    >
      {children}
    </div>
  );
}

import {
  getVariableOptions,
  useVariableOptions,
} from '../../utils/node-options';
import { processVariables } from '../../utils/variable';
import { ReactRenderer } from '@tiptap/react';
import { SuggestionOptions } from '@tiptap/suggestion';
import { forwardRef, useImperativeHandle, useRef } from 'react';
import tippy, { GetReferenceClientRect } from 'tippy.js';
import {
  DEFAULT_VARIABLE_TRIGGER_CHAR,
  Variable as VariableType,
} from './variable';
import { VariableSuggestionsPopoverRef } from './variable-suggestions-popover';

export type VariableListProps = {
  command: (params: {
    id: string;
    required: boolean;
    hideDefaultValue: boolean;
    label?: string;
  }) => void;
  items: VariableType[];
} & SuggestionOptions;

export const VariableList = forwardRef((props: VariableListProps, ref) => {
  const { items = [], editor } = props;

  const popoverRef = useRef<VariableSuggestionsPopoverRef>(null);
  const VariableSuggestionPopoverComponent =
    useVariableOptions(editor)?.variableSuggestionsPopover;

  useImperativeHandle(ref, () => ({
    onKeyDown: ({ event }: { event: KeyboardEvent }) => {
      if (!popoverRef.current) {
        return false;
      }

      const { moveUp, moveDown, select } = popoverRef.current || {};
      if (event.key === 'ArrowUp') {
        event.preventDefault();
        moveUp();
        return true;
      }

      if (event.key === 'ArrowDown') {
        event.preventDefault();
        moveDown();
        return true;
      }

      if (event.key === 'Enter') {
        select();
        return true;
      }

      return false;
    },
  }));

  return (
    <VariableSuggestionPopoverComponent
      items={items}
      onSelectItem={(value) => {
        props.command({
          id: value.name,
          required: value.required ?? true,
          hideDefaultValue: value?.hideDefaultValue ?? false,
          label: value?.label,
        });
      }}
      ref={popoverRef}
    />
  );
});

VariableList.displayName = 'VariableList';

export function getVariableSuggestions(
  char: string = DEFAULT_VARIABLE_TRIGGER_CHAR
): Omit<SuggestionOptions, 'editor'> {
  return {
    char,
    items: ({ query, editor }) => {
      const variables = getVariableOptions(editor)?.variables;

      return processVariables(variables, {
        query,
        editor,
        from: 'content-variable',
      });
    },

    render: () => {
      let component: ReactRenderer<any>;
      let popup: InstanceType<any> | null = null;

      return {
        onStart: (props) => {
          component = new ReactRenderer(VariableList, {
            props,
            editor: props.editor,
          });

          if (!props.clientRect) {
            return;
          }

          popup = tippy('body', {
            getReferenceClientRect: props.clientRect as GetReferenceClientRect,
            appendTo: () => document.body,
            content: component.element,
            showOnCreate: true,
            interactive: true,
            trigger: 'manual',
            placement: 'bottom-start',
          });
        },

        onUpdate(props) {
          component.updateProps(props);

          if (!props.clientRect) {
            return;
          }

          popup?.[0]?.setProps({
            getReferenceClientRect: props.clientRect as GetReferenceClientRect,
          });
        },

        onKeyDown(props) {
          if (props.event.key === 'Escape') {
            popup?.[0].hide();
            return true;
          }

          return component.ref?.onKeyDown(props);
        },

        onExit() {
          if (!popup || !popup?.[0] || !component) {
            return;
          }

          popup?.[0].destroy();
          component.destroy();
        },
      };
    },
  };
}

import { IconPlaceholder } from "@/components/icon-placeholder"
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from '../../components/popover';
import { Divider } from '../../components/ui/divider';
import { TooltipProvider } from '../../components/ui/tooltip';
import { cn } from '@/lib/utils';
import { AUTOCOMPLETE_PASSWORD_MANAGERS_OFF } from '../../utils/constants';
import { getNodeOptions } from '../../utils/node-options';
import { NodeViewProps } from '@tiptap/core';
import { NodeViewWrapper } from '@tiptap/react';
import { useMemo } from 'react';
import {
  DEFAULT_RENDER_VARIABLE_FUNCTION,
  VariableOptions,
  type RenderVariableFunction,
} from './variable';

export function VariableView(props: NodeViewProps) {
  const { node, updateAttributes, editor } = props;
  const {
    id,
    fallback,
    required,
    hideDefaultValue = false,
    label,
  } = node.attrs;

  const renderVariable = useMemo(() => {
    const variableRender =
      getNodeOptions<VariableOptions>(editor, 'variable')?.renderVariable ??
      DEFAULT_RENDER_VARIABLE_FUNCTION;

    return variableRender;
  }, [editor]);

  return (
    <NodeViewWrapper
      className="react-component inline-block leading-none"
      draggable="false"
    >
      <Popover
        onOpenChange={(open) => {
          editor.storage.variable.popover = open;
        }}
      >
        <PopoverTrigger>
          {renderVariable({
            variable: {
              name: id,
              required: required,
              valid: true,
              label,
            },
            fallback,
            editor,
            from: 'content-variable',
          })}
        </PopoverTrigger>
        <PopoverContent
          align="start"
          side="bottom"
          className="w-max rounded-lg p-0.5!"
          sideOffset={8}
          onOpenAutoFocus={(e) => e.preventDefault()}
          onCloseAutoFocus={(e) => e.preventDefault()}
        >
          <TooltipProvider>
            <div className="text-foreground flex items-stretch">
              <label className="relative">
                <span className="text-foreground inline-block px-2 text-xs">
                  Variable
                </span>
                <input
                  {...AUTOCOMPLETE_PASSWORD_MANAGERS_OFF}
                  value={id ?? ''}
                  onChange={(e) => {
                    updateAttributes({
                      id: e.target.value,
                    });
                  }}
                  placeholder="ie. name..."
                  className="bg-muted text-foreground focus:bg-muted h-7 w-36 rounded-md px-2 text-sm focus:outline-hidden disabled:cursor-not-allowed"
                />
              </label>

              {!hideDefaultValue && (
                <>
                  <Divider className="mx-1.5" />

                  <label className="relative">
                    <span className="text-foreground inline-block px-2 pl-1 text-xs">
                      Default
                    </span>
                    <input
                      {...AUTOCOMPLETE_PASSWORD_MANAGERS_OFF}
                      value={fallback ?? ''}
                      onChange={(e) => {
                        updateAttributes({
                          fallback: e.target.value,
                        });
                      }}
                      placeholder="ie. John Doe..."
                      className="bg-muted text-foreground focus:bg-muted h-7 w-32 rounded-md px-2 pr-6 text-sm focus:outline-none"
                    />
                    <div className="absolute inset-y-0 right-1 flex items-center">
                      <IconPlaceholder
  lucide="Pencil"
  tabler="IconPencil"
  hugeicons="PencilIcon"
  phosphor="Pencil"
  remixicon="RiPencilLine"
  className="text-foreground h-3 w-3 stroke-[2.5]"
/>
                    </div>
                  </label>
                </>
              )}
            </div>
          </TooltipProvider>
        </PopoverContent>
      </Popover>
    </NodeViewWrapper>
  );
}

export const DefaultRenderVariable: RenderVariableFunction = (props) => {
  const { variable, fallback, from } = props;
  const { name, required, valid, label } = variable;
  const variableLabel = label || name;

  if (from === 'button-variable') {
    return (
