        <IconPlaceholder
  lucide="Braces"
  tabler="IconBraces"
  hugeicons="BracesIcon"
  phosphor="BracketsCurly"
  remixicon="RiBracesLine"
  className="h-3 w-3 shrink-0 stroke-[2.5]"
/>
        <span className="min-w-0 truncate text-left">{variableLabel}</span>
