      <IconPlaceholder
  lucide="Braces"
  tabler="IconBraces"
  hugeicons="BracesIcon"
  phosphor="BracketsCurly"
  remixicon="RiBracesLine"
  className="size-[var(--variable-icon-size)] shrink-0 stroke-[2.5] text-rose-600"
