    },
    props: {
      handleDOMEvents: {
        mouseleave: (e, event) => (
          x ||
            (event.target &&
              !container.contains(event?.relatedTarget as Node) &&
              (null == tippyInstance || tippyInstance.hide(),
              (currentNode = null),
              (lastNodePos = -1),
              null == onNodeChange ||
