          const n = findElementNextToCoords({
            x: t.clientX,
            y: t.clientY,
            direction: 'right',
            editor: editor,
          });
          if (!n.resultElement) return false;
          let o = n.resultElement;
          if (((o = getOuterNodePos(e, o)), o === e.dom)) return false;
          if (1 !== (null == o ? undefined : o.nodeType)) return false;
          const r = e.posAtDOM(o, 0),
            s = getAncestorNodeAtDepth(editor.state.doc, r);
          if (s !== currentNode) {
            const t = getPreviousNodeStartPosition(editor.state.doc, r);
            (currentNode = s),
              (lastNodePos = t),
              getOuterNode(e.state, lastNodePos),
              null == onNodeChange ||
                onNodeChange({
                  editor: editor,
                  node: currentNode,
                  pos: lastNodePos,
                }),
              tippyInstance.setProps({
                getReferenceClientRect: () => o.getBoundingClientRect(),
              }),
              tippyInstance.show();
          }
          return false;
        },
      },
    },
  });
}

import React, { useState, useRef, useEffect } from 'react';

import { Node } from '@tiptap/pm/model';
import { ReactNode } from 'react';
import { Editor } from '@tiptap/core';
import { Props as TippyProps } from 'tippy.js';
import {
  DragHandlePlugin,
  dragHandlePluginDefaultKey,
} from './drag-handle-plugin';

export type DragHandleProps = {
  editor: Editor;
  pluginKey?: string;
  className?: string;
  tippyOptions?: Partial<TippyProps>;
  onNodeChange?: (data: {
    node: Node | null;
    editor: Editor;
    pos: number;
  }) => void;
  children: ReactNode;
};

export function DragHandle(props: DragHandleProps) {
  const {
    className = 'drag-handle',
    children,
    editor,
    pluginKey = dragHandlePluginDefaultKey,
    onNodeChange,
    tippyOptions = {},
  } = props;

  const [element, setElement] = useState<HTMLDivElement | null>(null);
  const pluginRef = useRef<ReturnType<typeof DragHandlePlugin> | null>(null);

  useEffect(() => {
    if (!element) {
      return () => {
        pluginRef.current = null;
      };
    }

    if (editor.isDestroyed) {
      return () => {
        pluginRef.current = null;
      };
    }

    if (!pluginRef.current) {
      pluginRef.current = DragHandlePlugin({
        editor,
        element,
        pluginKey,
        tippyOptions,
        onNodeChange,
      });

      editor.registerPlugin(pluginRef.current);
    }

    return () => {
      editor.unregisterPlugin(pluginKey);
      pluginRef.current = null;
    };
  }, [element, editor, onNodeChange, pluginKey]);

  return (
    <div className={className} ref={setElement}>
      {children}
    </div>
  );
}

import { Editor } from '@tiptap/core';
import { Node } from '@tiptap/pm/model';
import { Plugin, PluginKey } from '@tiptap/pm/state';
import { EditorView } from '@tiptap/pm/view';

export type ImageUploadPluginOptions = {
  editor: Editor;
  /**
   * Allows you to define a list of allowed mime types for dropped or pasted images.
   * @default ['image/jpeg', 'image/png', 'image/gif', 'image/webp', 'image/svg+xml']
   */
  allowedMimeTypes?: string[];

  /**
   * The onImageUpload callback that is called when an image is dropped or pasted.
   * @param file the image file
   * @returns Returns the image URL as a string.
   */
  onImageUpload?: (file: Blob) => Promise<string>;
};

export function ImageUploadPlugin(options: ImageUploadPluginOptions) {
  const { editor, onImageUpload, allowedMimeTypes } = options;

  function handleImageUpload(view: EditorView, file: File, pos?: number) {
    const placeholderSrc = URL.createObjectURL(file);

    const { tr, schema } = view.state;
    const imageNode = schema.nodes.image.create({
      src: placeholderSrc,
      isSrcVariable: false,
      alt: file.name,
      externalLink: '',
      isExternalLinkVariable: false,
    });
    editor?.extensionStorage?.imageUpload?.placeholderImages?.add(
      placeholderSrc
    );

    const resolvedPos =
      pos !== undefined
        ? view.state.doc.resolve(pos)
        : view.state.selection.$head;

    const transaction = tr.insert(resolvedPos.pos, imageNode);
    view.dispatch(transaction);

    onImageUpload?.(file)
      .then((uploadedSrc) => {
        const updateTr = view.state.tr;

        // Find the placeholder image node
        const predicate = (node: Node) =>
          node.type.name === 'image' && node.attrs.src === placeholderSrc;

        view.state.doc.descendants((node, pos) => {
          if (predicate(node)) {
            updateTr.setNodeMarkup(pos, undefined, {
              ...node.attrs,
              src: uploadedSrc,
            });
            return false;
          }
        });

        view.dispatch(updateTr);
      })
      .catch((error) => {
        console.error('Image upload failed', error);
      })
      .finally(() => {
        editor.extensionStorage.imageUpload.placeholderImages.delete(
          placeholderSrc
        );
        URL.revokeObjectURL(placeholderSrc);
      });
  }

  return new Plugin({
    key: new PluginKey('imageUpload'),
    props: {
      handleDrop: (view, event) => {
        if (
          !onImageUpload ||
          // we'll handle drops in the ImageView component
          // this is just for dropping images in empty areas
          !event.dataTransfer?.files?.length
        ) {
          return false;
        }

        const images = Array.from(event.dataTransfer.files).filter((file) =>
          allowedMimeTypes?.includes(file.type)
        );
        if (images.length === 0) {
          return false;
        }

        const pos = view.posAtCoords({
          left: event.clientX,
          top: event.clientY,
        });
        if (!pos) {
          return false;
        }

        event.preventDefault();
        event.stopPropagation();

        images.forEach((file) => handleImageUpload(view, file, pos.pos));
        return true;
      },
      handlePaste: (view, event) => {
        if (!onImageUpload || !event.clipboardData?.files?.length) {
          return false;
        }

        const images = Array.from(event.clipboardData.files).filter((file) =>
          allowedMimeTypes?.includes(file.type)
        );
        if (images.length === 0) {
          return false;
        }

        event.preventDefault();
        event.stopPropagation();

        images.forEach((file) => handleImageUpload(view, file));
        return true;
      },
    },
  });
}

