export type MailyContextType = {
  placeholderUrl?: string;
  blocks?: BlockGroupItem[];
  labels: MailyLabels;
  t: TranslateFn;
};

export const MailyContext = createContext<MailyContextType>({
  placeholderUrl: DEFAULT_PLACEHOLDER_URL,
  blocks: getDefaultBlocks(englishTranslator),
  labels: { ...defaultLabels },
  t: englishTranslator,
});

type MailyProviderProps = PropsWithChildren<MailyContextType>;

export function MailyProvider(props: MailyProviderProps) {
  const { children, ...values } = props;
  const value = useMemo(
    () => values,
    [values.placeholderUrl, values.blocks, values.labels, values.t]
  );

  return <MailyContext.Provider value={value}>{children}</MailyContext.Provider>;
}

export function useMailyContext() {
  const values = useContext(MailyContext);
  if (!values) {
    throw new Error('Missing MailyContext.Provider in the component tree');
  }

  return values;
}

/**
 * Calculates the aspect ratio from image dimensions
 * @param width - The width of the image
 * @param height - The height of the image
 * @returns The aspect ratio as width/height
 */
export function getAspectRatio(width: number, height: number): number {
  return width / height;
}

/**
 * Calculates new height based on width and aspect ratio
 * @param width - The new width
 * @param aspectRatio - The aspect ratio (width/height)
 * @returns The corresponding height
 */
export function getNewHeight(width: number, aspectRatio: number): number {
  if (width <= 0 || aspectRatio <= 0) {
    return 0;
  }
  return width / aspectRatio;
}

/**
 * Calculates new width based on height and aspect ratio
 * @param height - The new height
 * @param aspectRatio - The aspect ratio (width/height)
 * @returns The corresponding width
 */
export function getNewWidth(height: number, aspectRatio: number): number {
  return height * aspectRatio;
}

