import { findParentNode, type Editor } from '@tiptap/core';

export function deleteNode(editor: Editor, nodeType: string) {
  const { state } = editor.view;
  const associatedNode = findParentNode((node) => node.type.name === nodeType)(
    state.selection
  );

  if (!associatedNode) {
    return;
  }

  const from = associatedNode.pos;
  const to = from + associatedNode.node.nodeSize;

  const { tr } = state;
  const transaction = tr.delete(from, to);
  editor.view.dispatch(transaction);
}

import { Editor } from '@tiptap/react';

export function getRenderContainer(editor: Editor, nodeType: string) {
  const {
    view,
    state: {
      selection: { from },
    },
  } = editor;

  const elements = document.querySelectorAll('.has-focus');
  const elementCount = elements.length;
  const innermostNode = elements[elementCount - 1];
  const element = innermostNode;

  if (
    (element &&
      element.getAttribute('data-type') &&
      element.getAttribute('data-type') === nodeType) ||
    (element &&
      element.classList &&
      (element.classList.contains(nodeType) ||
        element.classList.contains(`node-${nodeType}`)))
  ) {
    return element;
  }

  const node = view.domAtPos(from).node as HTMLElement;
  let container: HTMLElement | null = node;

  if (!container.tagName) {
    container = node.parentElement;
  }

  while (
    container &&
    !(
      container.getAttribute('data-type') &&
      container.getAttribute('data-type') === nodeType
    ) &&
    !container.classList.contains(nodeType)
  ) {
    container = container.parentElement;
  }

  return container;
}

