export const isCustomNodeSelected = (editor: Editor, node: HTMLElement) => {
  const customNodes = [
    HorizontalRule.name,
    Image.name,
    Spacer.name,
    ImageExtension.name,
    VariableExtension.name,
    LinkCardExtension.name,
    LogoExtension.name,
    ButtonExtension.name,
    HTMLCodeBlockExtension.name,
    InlineImageExtension.name,
  ];

  return customNodes.some((type) => editor.isActive(type));
};

import { isTextSelection } from '@tiptap/core';
import { Editor } from '@tiptap/react';

export function isTextSelected(editor: Editor) {
  const {
    state: {
      doc,
      selection,
      selection: { empty, from, to },
    },
  } = editor;

  // Sometime check for `empty` is not enough.
  // Doubleclick an empty paragraph returns a node size of 2.
  // So we check also for an empty text size.
  const isEmptyTextBlock =
    !doc.textBetween(from, to).length && isTextSelection(selection);

  if (empty || isEmptyTextBlock || !editor.isEditable) {
    return false;
  }

  return true;
}

import type { Editor } from '@tiptap/core';
import { type VariableOptions } from '../nodes/variable/variable';
import { useMemo } from 'react';

export function getNodeOptions<T extends Record<string, unknown>>(
  editor: Editor,
  name: string
): T {
  const node = editor.extensionManager.extensions.find(
    (extension) => extension.name === name
  );

  if (!node) {
    throw new Error(`Node ${name} not found`);
  }

  return node.options as T;
}

export function getVariableOptions(editor: Editor) {
  return getNodeOptions<VariableOptions>(editor, 'variable');
}

export function useVariableOptions(editor: Editor) {
  return useMemo(() => {
    return getVariableOptions(editor);
  }, [editor]);
}

import { JSONContent } from '@tiptap/core';
import { spacing } from './spacing';
import { DEFAULT_SPACER_HEIGHT } from '../../extensions';

/**
 * To replace deprecated node type or attributes
 * to avoid breaking changes, we can replace the deprecated node type or attributes
 * with the new one in the JSON content object.
 * @param json - previous JSON content object
 * @returns JSONContent - new JSON content object
 */
export function replaceDeprecatedNode(json: JSONContent) {
  const stack = [json];

  while (stack.length) {
    const node = stack.pop();
    if (!node) {
      continue;
    }

    if (node.type === 'for') {
      node.type = 'repeat';
    }

    if (node.type === 'spacer') {
      let height = node.attrs?.height;
      if (
        typeof height === 'string' &&
        ['sm', 'md', 'lg', 'xl'].includes(height)
      ) {
        height =
          spacing.find((s) => s.short === height)?.value ||
          DEFAULT_SPACER_HEIGHT;
      }

      node.attrs = {
        ...node.attrs,
        height,
      };
    }

    if (node.content) {
      stack.push(...node.content);
    }
  }

  return json;
}

