  private columns(node: JSONContent, options?: NodeOptions): JSX.Element {
    const { attrs } = node;

    const shouldShow = this.shouldShow(node, options);
    if (!shouldShow) {
      return <></>;
    }

    const [newNode, totalWidth] = this.adjustColumnsContent(node);

    return (
      <Row
        width={`${totalWidth}%`}
        style={{
          margin: 0,
          padding: 0,
          width: `${totalWidth}%`,
        }}
        className="tab-row-full"
      >
        {this.getMappedContent(newNode, {
          ...options,
          parent: newNode,
        })}
      </Row>
    );
  }

  private adjustColumnsContent(node: JSONContent): [JSONContent, number] {
    const { content = [] } = node;
    const totalWidth = 100;
    const columnsWithWidth = content.filter(
      (c) => c.type === 'column' && Boolean(Number(c.attrs?.width || 0))
    );
    const autoWidthColumns = content.filter(
      (c) =>
        c.type === 'column' && (c.attrs?.width === 'auto' || !c.attrs?.width)
    );

    const totalWidthUsed = columnsWithWidth.reduce(
      (acc, c) => acc + Number(c.attrs?.width),
      0
    );

    const remainingWidth = totalWidth - totalWidthUsed;
    const measuredWidth = Math.round(remainingWidth / autoWidthColumns.length);

    const columnCount = content.filter((c) => c.type === 'column').length;
    const gap = node.attrs?.gap ?? DEFAULT_COLUMNS_GAP;

    return [
      {
        ...node,
        content: content.map((c, index) => {
          const isAutoWidthColumn =
            c.type === 'column' &&
            (c.attrs?.width === 'auto' || !c.attrs?.width);
          const isFirstColumn = index === 0;
          const isMiddleColumn = index > 0 && index < columnCount - 1;
          const isLastColumn = index === content.length - 1;

          let paddingLeft = 0;
          let paddingRight = 0;

          // For 2 columns, apply a simple gap logic
          if (columnCount < 3) {
            paddingLeft = isFirstColumn ? 0 : gap / 2;
            paddingRight = isLastColumn ? 0 : gap / 2;
          } else {
            // For more than 2 columns, apply more gap in the first and last columns
            // and less gap in the middle columns to make it look more balanced
            // because the first and last columns have more space to fill
            const leftAndRightPadding = (gap / 2) * 1.5;
            const middleColumnPadding = leftAndRightPadding / 2;

            paddingLeft = isFirstColumn
              ? 0
              : isMiddleColumn
                ? middleColumnPadding
                : leftAndRightPadding;
            paddingRight = isLastColumn
              ? 0
              : isMiddleColumn
                ? middleColumnPadding
                : leftAndRightPadding;
          }

          paddingLeft = Math.round(paddingLeft * 100) / 100;
          paddingRight = Math.round(paddingRight * 100) / 100;

          return {
            ...c,
            attrs: {
              ...c.attrs,
              width: isAutoWidthColumn ? measuredWidth : c.attrs?.width,

              isFirstColumn,
              isLastColumn,
              index,

              paddingLeft,
              paddingRight,
            },
          };
        }),
      },
      autoWidthColumns.length === 0
        ? Math.min(totalWidth, totalWidthUsed)
        : totalWidth,
    ];
  }

  private column(node: JSONContent, options?: NodeOptions): JSX.Element {
    const { attrs } = node;
    const {
      width,
      verticalAlign = 'top',
      paddingLeft = 0,
      paddingRight = 0,
    } = attrs || {};

    return (
      <Column
        width={`${Number(width)}%`}
        style={{
          width: `${Number(width)}%`,
          margin: 0,
          verticalAlign,
        }}
        className="tab-col-full"
      >
        <Section
          style={{
            margin: 0,
            paddingLeft,
            paddingRight,
          }}
          className="tab-pad"
        >
          {this.getMappedContent(node, {
            ...options,
            parent: node,
          })}
        </Section>
      </Column>
    );
  }

  private repeat(node: JSONContent, options?: NodeOptions): JSX.Element {
    const { attrs } = node;
    const { each = '' } = attrs || {};

    const shouldShow = this.shouldShow(node, options);
    if (!shouldShow) {
      return <></>;
    }

    let { payloadValue } = options || {};
    payloadValue = typeof payloadValue === 'object' ? payloadValue : {};

    const values = this.payloadValues.get(each) ?? payloadValue[each] ?? [];
    if (!Array.isArray(values)) {
      throw new Error(`Payload value for each "${each}" is not an array`);
    }

    return (
      <>
        {values.map((value) => {
          return (
            <Fragment key={generateKey()}>
              {this.getMappedContent(node, {
                ...options,
                parent: node,
                payloadValue: value,
              })}
            </Fragment>
          );
        })}
      </>
    );
  }

  /**
   * @deprecated
   * This for node is an alias for the repeat node
   * we will remove this in the future
   * @param node
   * @param options
   * @returns JSX.Element
   */
  private for(node: JSONContent, options?: NodeOptions): JSX.Element {
    return this.repeat(node, options);
  }

  private shouldShow(node: JSONContent, options?: NodeOptions): boolean {
    const showIfKey = node?.attrs?.showIfKey ?? '';
    if (!showIfKey) {
      return true;
    }

    let { payloadValue } = options || {};
    payloadValue = typeof payloadValue === 'object' ? payloadValue : {};
    return !!(this.payloadValues.get(showIfKey) ?? payloadValue[showIfKey]);
  }

  htmlCodeBlock(node: JSONContent, options?: NodeOptions): JSX.Element {
    const show = this.shouldShow(node, options);
    if (!show) {
      return <></>;
    }

    // the text can be a proper html code block
    // or only the body of the html
    // so we need to wrap it in a proper html tag
    const text =
      node.content?.reduce((acc, n) => {
        if (n?.type === 'text') {
          return acc + n?.text;
        } else if (n?.type === 'variable') {
          const value = this.getVariableValue(
            n?.attrs?.id,
            n?.attrs?.fallback,
            options
          );
          return acc + value;
        }

        return acc;
      }, '') || '';

    // we will inline the css in the html
    // so that it can be rendered properly
    const inlineCssHtml = juice(text);
    const doc = parse(inlineCssHtml);
    const head = doc?.querySelector('head');
    head?.remove();
    const html = doc.toString();

    return (
      <table
        align="left"
        width="100%"
        border={0}
        cellPadding="0"
        cellSpacing="0"
        role="presentation"
      >
        <tbody>
          <tr style={{ width: '100%' }}>
            <td
              style={{ width: '100%' }}
              dangerouslySetInnerHTML={{
                __html: html,
              }}
            />
          </tr>
        </tbody>
      </table>
    );
  }

  private inlineImage(node: JSONContent, options?: NodeOptions): JSX.Element {
    const { attrs } = node;
    let {
      src,
      isSrcVariable,
      alt = '',
      title = '',
      height = DEFAULT_INLINE_IMAGE_HEIGHT,
      width = DEFAULT_INLINE_IMAGE_WIDTH,
      externalLink = '',
      isExternalLinkVariable,
    } = attrs || {};

    src = isSrcVariable ? this.variableUrlValue(src, options) : src;
    externalLink = isExternalLinkVariable
      ? this.variableUrlValue(externalLink, options)
      : externalLink;

    const image = (
      <img
        src={src}
        alt={alt}
        title={title}
        width={width}
        height={height}
        style={{
          display: 'inline',
          verticalAlign: 'middle',
          width: `${width}px`,
          height: `${height}px`,
          outline: 'none',
          border: 'none',
          textDecoration: 'none',
        }}
      />
    );

    if (!externalLink) {
      return image;
    }

    return (
      <a
        href={externalLink}
        rel="noopener noreferrer"
        style={{
          display: 'inline',
          textDecoration: 'none',
        }}
        target="_blank"
      >
        {image}
      </a>
    );
  }
}

export type MetaDescriptor =
  | {
      charSet: 'utf-8';
    }
  | {
      title: string;
    }
  | {
      name: string;
      content: string;
    }
  | {
      property: string;
      content: string;
    }
  | {
      httpEquiv: string;
      content: string;
    }
  | {
      tagName: 'meta' | 'link';
      [attribute: string]: string;
    }
  | {
      [name: string]: string;
    };

export type MetaDescriptors = MetaDescriptor[];

export function meta(meta: MetaDescriptors) {
  return (
    meta
      // only filter unique meta tags
      // so that we don't have duplicate meta tags
      .filter((meta, index, self) => {
        const meta_hash = hash(meta);
        return (
          index ===
          self.findIndex((t) => {
            return hash(t) === meta_hash;
          })
        );
      })
      .map(process)
      .filter(Boolean) as JSX.Element[]
  );
}

function process(props: MetaDescriptor) {
  if ('tagName' in props) {
    const { tagName, ...attributes } = props;
    const Comp = tagName;
    return <Comp key={JSON.stringify(attributes)} {...attributes} />;
  }

  if ('title' in props) {
    return <title>{props.title}</title>;
  }

  if ('charSet' in props) {
    return <meta charSet={props.charSet} />;
  }

  return <meta key={JSON.stringify(props)} {...props} />;
}

/**
 * hash the meta object to string
 * so that we can filter out duplicates
 * for that we have to sort the object keys
 * and then stringify it and hash it
 */
function hash(meta: MetaDescriptor) {
  const sortedMeta = Object.keys(meta)
    .sort()
    .reduce((acc, key) => {
      const _key = key as keyof MetaDescriptor;
      acc[_key] = meta[_key];
      return acc;
    }, {} as MetaDescriptor);

  return JSON.stringify(sortedMeta);
}

import { JSONContent } from '@tiptap/core';
import { Maily } from './maily';

export class Preheader {
  constructor(private readonly maily: Maily) {}

  render(content: string | JSONContent): string {
    if (typeof content === 'string') {
      return content;
    }

    return this.renderNode(content);
  }

  private renderNode(node: JSONContent): string {
    const type = node.type || '';
    switch (type) {
      case 'doc':
        return this.doc(node);
      case 'paragraph':
        return this.paragraph(node);
      case 'text':
        return this.text(node);
      case 'variable':
        return this.variable(node);
      default:
        // it's fine to ignore unknown nodes
        // because we don't want to break the rendering process
        return '';
    }
  }

  private doc(node: JSONContent): string {
    const children = node.content || [];
    if (children.length === 0) {
      return '';
    }

    return children.map((child) => this.renderNode(child)).join('');
  }

  private paragraph(node: JSONContent): string {
    const children = node.content || [];
    if (children.length === 0) {
      return '';
    }

    return children.map((child) => this.renderNode(child)).join('');
  }

  private text(node: JSONContent): string {
    return node.text || '';
  }

  private variable(node: JSONContent): string {
    const { id: variable, fallback } = node.attrs || {};
    return this.maily.getVariableValue(variable, fallback);
  }
}

import type { JSONContent } from '@tiptap/core';
import { Maily } from './maily';
import type { MailyConfig, RenderOptions } from './maily';

export async function render(
  content: JSONContent,
  config?: MailyConfig & RenderOptions
): Promise<string> {
  const { theme, preview, ...rest } = config || {};

  const maily = new Maily(content);
  maily.setPreviewText(preview);
  maily.setTheme(theme || {});

  return maily.render(rest);
}

import type * as CSS from 'csstype';
import { DEFAULT_FONT, type EditorThemeOptions } from './theme';

declare module 'csstype' {
  interface Properties {
    [index: `--mly-${string}`]: any;
  }
}

/**
 * if the value is undefined, it will return an empty object
 * so that we don't override the default value
 * @param name - The name of the CSS variable
 * @param value - The value of the CSS variable
 * @returns The CSS variable value
 */
export function getVariableValue(
  name: `--mly-${string}`,
  value: any
): CSS.Properties {
  if (value === undefined || value === null || value === '') {
    return {};
  }

  return {
    [name]: value,
  };
}

/**
 * Get the CSS variables for the theme
 * @param theme - The theme
 * @returns The CSS variables
 * @example
 * ```ts
 * const theme = {
 *   body: {
 *     backgroundColor: 'red',
 *   },
 * };
 *
 * const cssVariables = getCssVariables(theme);
 *
 * console.log(cssVariables);
 * // { '--mly-body-background-color': 'red' }
 */
export function getMailyCssVariables(
  theme: EditorThemeOptions
): CSS.Properties {
  const font = theme.font || DEFAULT_FONT;

  return {
    ...getVariableValue(
      '--mly-body-background-color',
      theme.body?.backgroundColor
    ),
    ...getVariableValue('--mly-body-padding-top', theme.body?.paddingTop),
    ...getVariableValue('--mly-body-padding-right', theme.body?.paddingRight),
    ...getVariableValue('--mly-body-padding-bottom', theme.body?.paddingBottom),
    ...getVariableValue('--mly-body-padding-left', theme.body?.paddingLeft),

    ...getVariableValue(
      '--mly-container-background-color',
      theme.container?.backgroundColor
    ),
    ...getVariableValue('--mly-container-max-width', theme.container?.maxWidth),
    ...getVariableValue('--mly-container-min-width', theme.container?.minWidth),

    ...getVariableValue(
      '--mly-container-padding-top',
      theme.container?.paddingTop
    ),
    ...getVariableValue(
      '--mly-container-padding-right',
      theme.container?.paddingRight
    ),
    ...getVariableValue(
      '--mly-container-padding-bottom',
      theme.container?.paddingBottom
    ),
    ...getVariableValue(
      '--mly-container-padding-left',
      theme.container?.paddingLeft
    ),

    ...getVariableValue(
      '--mly-container-border-radius',
      theme.container?.borderRadius
    ),
    ...getVariableValue(
      '--mly-container-border-width',
      theme.container?.borderWidth
    ),
    ...getVariableValue(
      '--mly-container-border-color',
      theme.container?.borderColor
    ),

    ...getVariableValue(
      '--mly-button-background-color',
      theme.button?.backgroundColor
    ),
    ...getVariableValue('--mly-button-text-color', theme.button?.color),
    ...getVariableValue('--mly-button-padding-top', theme.button?.paddingTop),
    ...getVariableValue(
      '--mly-button-padding-right',
      theme.button?.paddingRight
    ),
    ...getVariableValue(
      '--mly-button-padding-bottom',
      theme.button?.paddingBottom
    ),
    ...getVariableValue('--mly-button-padding-left', theme.button?.paddingLeft),

    ...getVariableValue('--mly-link-color', theme.link?.color),

    ...getVariableValue('--mly-font-family', font.fontFamily),
    ...getVariableValue('--mly-font-fallback-family', font.fallbackFontFamily),
    '--mly-font': `var(--mly-font-family), var(--mly-font-fallback-family)`,
  };
}

import type { FontProps } from './theme';

type Font = Pick<FontProps, 'fontFamily' | 'fallbackFontFamily' | 'webFont'>;

export function loadFont(font: Font): void {
  const style = fontStyle(font);

  const styleElement = document.createElement('style');
  styleElement.textContent = style;
  document.head.appendChild(styleElement);
}

export function fontStyle(font: Font): string {
  const { fontFamily, fallbackFontFamily, webFont } = font;

  const src = webFont
    ? `src: url(${webFont.url}) format('${webFont.format}');`
    : '';

  const style = `
  @font-face {
    font-family: '${fontFamily}';
    font-style: normal;
    font-weight: 400;
    mso-font-alt: '${fallbackFontFamily}';
    ${src}
  }`;

  return style;
}

